var documenterSearchIndex = {"docs":
[{"category":"section","location":"components/#Components-Guide","page":"Components","text":"Components are the building blocks for creating reusable, maintainable templates in HypertextTemplates.jl. This guide covers everything from basic component creation to advanced patterns.","title":"Components Guide"},{"category":"section","location":"components/#Basic-Component-Definition","page":"Components","text":"Components are defined using the @component macro applied to a function:\n\nusing HypertextTemplates\nusing HypertextTemplates.Elements\n\n@component function greeting(; name = \"World\")\n    @div {class = \"greeting\"} begin\n        @h1 \"Hello, \" $name \"!\"\n    end\nend\n\n# Important: Define a macro for the component\n@deftag macro greeting end\n\n# Now you can use it\nhtml = @render @greeting {name = \"Julia\"}\n\nMain.display_html(html) #hide\n\n# Also works with default value\nhtml2 = @render @greeting\n\nMain.display_html(html2) #hide","title":"Basic Component Definition"},{"category":"section","location":"components/#Component-Properties-(Props)","page":"Components","text":"Props are passed as keyword arguments to component functions:","title":"Component Properties (Props)"},{"category":"section","location":"components/#Required-Props","page":"Components","text":"Omit default values to make props required:\n\nusing HypertextTemplates\nusing HypertextTemplates.Elements\n\n@component function user_card(; username, email)  # Both required\n    @div {class = \"user-card\"} begin\n        @h3 $username\n        @p $email\n    end\nend\n\n@deftag macro user_card end\n\n# Must provide both props\nhtml = @render @user_card {username = \"julia_dev\", email = \"julia@example.com\"}\nMain.display_html(html) #hide","title":"Required Props"},{"category":"section","location":"components/#Optional-Props-with-Defaults","page":"Components","text":"using HypertextTemplates\nusing HypertextTemplates.Elements\n\n@component function my_button(; \n    text = \"Click me\",\n    type = \"button\",\n    variant = \"primary\",\n    disabled = false\n)\n    classes = \"btn btn-\" * variant\n    @button {type, class = classes, disabled} $text\nend\n\n@deftag macro my_button end\n\n# Use with defaults\n@render @my_button {}\n\nMain.display_html(ans) #hide\n\n# Override specific props\n@render @my_button {text = \"Submit\", variant = \"success\"}\n\nMain.display_html(ans) #hide\n\n# With disabled state\n@render @my_button {text = \"Loading...\", disabled = true}\nMain.display_html(ans) #hide","title":"Optional Props with Defaults"},{"category":"section","location":"components/#Typed-Props","page":"Components","text":"Leverage Julia's type system for safer components:\n\nusing HypertextTemplates\nusing HypertextTemplates.Elements\n\n@component function product_price(; \n    amount::Number,\n    currency::String = \"USD\",\n    decimal_places::Int = 2\n)\n    formatted = round(amount, digits = decimal_places)\n    @span {class = \"price\"} begin\n        @span {class = \"currency\"} $currency\n        @span {class = \"amount\"} $formatted\n    end\nend\n\n@deftag macro product_price end\n\n# Usage with different types\n@render @product_price {amount = 29.99}\n\nMain.display_html(ans) #hide\n\n@render @product_price {amount = 100, currency = \"EUR\", decimal_places = 0}\n\nMain.display_html(ans) #hide","title":"Typed Props"},{"category":"section","location":"components/#Slots-System","page":"Components","text":"Slots allow components to accept content from their parent, enabling flexible composition.","title":"Slots System"},{"category":"section","location":"components/#Default-Slot","page":"Components","text":"The simplest form - a single content area:\n\nusing HypertextTemplates\nusing HypertextTemplates.Elements\n\n@component function card(; title)\n    @div {class = \"card\"} begin\n        @div {class = \"card-header\"} @h3 $title\n        @div {class = \"card-body\"} begin\n            @__slot__  # Default slot receives content\n        end\n    end\nend\n\n@deftag macro card end\n\n# Usage with content\nhtml = @render @card {title = \"User Profile\"} begin\n    @p \"Name: Alice\"\n    @p \"Role: Developer\"\nend\nMain.display_html(html) #hide","title":"Default Slot"},{"category":"section","location":"components/#Named-Slots","page":"Components","text":"For more complex layouts with multiple content areas:\n\nusing HypertextTemplates\nusing HypertextTemplates.Elements\n\n@component function layout()\n    @div {class = \"layout\"} begin\n        @header {class = \"layout-header\"} begin\n            @__slot__ header  # Named slot: header\n        end\n        @article {class = \"layout-main\"} begin\n            @__slot__  # Default slot\n        end\n        @footer {class = \"layout-footer\"} begin\n            @__slot__ footer  # Named slot: footer\n        end\n    end\nend\n\n@deftag macro layout end\n\n# Usage with named slots\nhtml = @render @layout begin\n    # Named slot content uses := syntax\n    header := begin\n        @h1 \"My Application\"\n        @nav begin\n            @a {href = \"/\"} \"Home\"\n            @a {href = \"/about\"} \"About\"\n        end\n    end\n\n    # Default slot content\n    @section begin\n        @h2 \"Welcome\"\n        @p \"This is the main content area.\"\n    end\n\n    footer := @p \"© 2024 My Company\"\nend\n\nMain.display_html(html) #hide","title":"Named Slots"},{"category":"section","location":"components/#Conditional-Slots","page":"Components","text":"Slots can be conditionally rendered:\n\nusing HypertextTemplates\nusing HypertextTemplates.Elements\n\n@component function message(; type = \"info\", dismissible = false)\n    @div {class = \"message message-$type\"} begin\n        @__slot__  # Message content\n\n        if dismissible\n            @button {class = \"message-close\"} begin\n                @__slot__ close_button  # Optional slot\n            end\n        end\n    end\nend\n\n@deftag macro message end\n\n# Without close button content\nhtml1 = @render @message {type = \"warning\"} begin\n    @p \"This is a warning\"\nend\n\nMain.display_html(html1) #hide\n\n# With custom close button\nhtml2 = @render @message {type = \"error\", dismissible = true} begin\n    @p \"An error occurred\"\n    close_button := @span \"×\"\nend\n\nMain.display_html(html2) #hide","title":"Conditional Slots"},{"category":"section","location":"components/#Slot-Fallbacks","page":"Components","text":"Provide default content when slots are empty:\n\nusing HypertextTemplates\nusing HypertextTemplates.Elements\n\n@component function avatar(; src = nothing, alt = \"\")\n    @div {class = \"avatar\"} begin\n        if !isnothing(src)\n            @img {src, alt}\n        else\n            @div {class = \"avatar-placeholder\"} begin\n                # Show slot content (initials)\n                @__slot__\n            end\n        end\n    end\nend\n\n@deftag macro avatar end\n\n# With image\nhtml1 = @render @avatar {src = \"/user.jpg\", alt = \"User\"}\n\nMain.display_html(html1) #hide\n\n# With placeholder (slot content)\nhtml2 = @render @avatar {alt = \"John Doe\"} begin\n    @span \"JD\"  # Initials as fallback\nend\n\nMain.display_html(html2) #hide","title":"Slot Fallbacks"},{"category":"section","location":"components/#Component-Composition","page":"Components","text":"Components can use other components, enabling powerful composition patterns:","title":"Component Composition"},{"category":"section","location":"components/#Basic-Composition","page":"Components","text":"using HypertextTemplates\nusing HypertextTemplates.Elements\n\n@component function nav_link(; href, active = false)\n    class = active ? \"nav-link active\" : \"nav-link\"\n    @a {href, class} @__slot__\nend\n\n@deftag macro nav_link end\n\n@component function navbar(; links, current_path = \"/\")\n    @nav {class = \"navbar\"} begin\n        @ul begin\n            for link in links\n                @li begin\n                    @nav_link {\n                        href = link.href,\n                        active = link.href == current_path\n                    } begin\n                        @text link.text\n                    end\n                end\n            end\n        end\n    end\nend\n\n@deftag macro navbar end\n\n# Usage\nlinks = [\n    (href = \"/\", text = \"Home\"),\n    (href = \"/about\", text = \"About\"),\n    (href = \"/contact\", text = \"Contact\")\n]\n\nhtml = @render @navbar {links, current_path = \"/about\"}\n\nMain.display_html(html) #hide","title":"Basic Composition"},{"category":"section","location":"components/#Higher-Order-Components","page":"Components","text":"Create components that modify behavior of other components:\n\nusing HypertextTemplates\nusing HypertextTemplates.Elements\n\n@component function with_tooltip(; tooltip, position = \"top\")\n    @div {\n        class = \"tooltip-wrapper\",\n        \"data-tooltip\" := tooltip,\n        \"data-position\" := position\n    } begin\n        @__slot__\n    end\nend\n\n@deftag macro with_tooltip end\n\n# Wrap any content with tooltip\nhtml = @render @with_tooltip {tooltip = \"Click to submit\"} begin\n    @button \"Submit\"\nend\n\nMain.display_html(html) #hide","title":"Higher-Order Components"},{"category":"section","location":"components/#Component-Arrays","page":"Components","text":"Render collections of components:\n\nusing HypertextTemplates\nusing HypertextTemplates.Elements\n\n@component function todo_item(; task, completed = false)\n    @li {class = completed ? \"completed\" : \"\"} begin\n        @input {type = \"checkbox\", checked = completed}\n        @span \" \" $task\n    end\nend\n\n@deftag macro todo_item end\n\n@component function todo_list(; items)\n    @ul {class = \"todo-list\"} begin\n        for item in items\n            @todo_item {task = item.task, completed = item.completed}\n        end\n    end\nend\n\n@deftag macro todo_list end\n\n# Example usage\nitems = [\n    (task = \"Write documentation\", completed = true),\n    (task = \"Add tests\", completed = false),\n    (task = \"Deploy to production\", completed = false)\n]\n\nhtml = @render @todo_list {items}\n\nMain.display_html(html) #hide","title":"Component Arrays"},{"category":"section","location":"components/#Dynamic-Components","page":"Components","text":"Use the @< macro to render components dynamically:","title":"Dynamic Components"},{"category":"section","location":"components/#Component-as-Props","page":"Components","text":"using HypertextTemplates\nusing HypertextTemplates.Elements\n\n@component function flexible_layout(; \n    header_component = nothing,\n    main_component = article,\n    sidebar = true\n)\n    @div {class = \"layout\"} begin\n        if !isnothing(header_component)\n            @<header_component\n        end\n\n        @<main_component {class = \"main-content\"} begin\n            @__slot__\n        end\n\n        if sidebar\n            @aside {class = \"sidebar\"} begin\n                @__slot__ sidebar\n            end\n        end\n    end\nend\n\n@deftag macro flexible_layout end\n\n# Custom header component\n@component function custom_header()\n    @header {class = \"fancy-header\"} begin\n        @h1 \"My App\"\n    end\nend\n\n# Usage\nhtml = @render @flexible_layout {\n    header_component = custom_header,\n    main_component = section\n} begin\n    @p \"Main content here\"\n    sidebar := @p \"Sidebar content\"\nend\n\nMain.display_html(html) #hide","title":"Component as Props"},{"category":"section","location":"components/#Conditional-Component-Selection","page":"Components","text":"using HypertextTemplates\nusing HypertextTemplates.Elements\n\n# Define icon components\n@component function error_icon()\n    @span {class = \"icon icon-error\"} \"❌\"\nend\n\n@component function warning_icon()\n    @span {class = \"icon icon-warning\"} \"⚠️\"\nend\n\n@component function info_icon()\n    @span {class = \"icon icon-info\"} \"ℹ️\"\nend\n\n@component function alert(; type = \"info\", message)\n    # Select icon based on type\n    icon_component = if type == \"error\"\n        error_icon\n    elseif type == \"warning\"\n        warning_icon\n    else\n        info_icon\n    end\n\n    @div {class = \"alert alert-$type\"} begin\n        @<icon_component\n        @span \" \"\n        @span $message\n    end\nend\n\n@deftag macro alert end\n\n# Test different alert types\n@render @alert {type = \"info\", message = \"This is information\"}\n\nMain.display_html(ans)\n\n@render @alert {type = \"warning\", message = \"This is a warning\"}\n\nMain.display_html(ans) #hide\n\n@render @alert {type = \"error\", message = \"This is an error\"}\nMain.display_html(ans) #hide","title":"Conditional Component Selection"},{"category":"section","location":"components/#Module-Qualified-Components","page":"Components","text":"Components can be organized in modules and referenced with qualification:\n\nusing HypertextTemplates\nusing HypertextTemplates.Elements\n\nmodule UI\n    using HypertextTemplates\n    using HypertextTemplates.Elements\n\n    @component function my_button(; variant = \"primary\")\n        @button {class = \"ui-button ui-button-$variant\"} @__slot__\n    end\n\n    @deftag macro my_button end\n\n    @component function card()\n        @div {class = \"ui-card\"} @__slot__\n    end\n\n    @deftag macro card end\nend\n\n# Usage with module qualification\nhtml = @render @div begin\n    @UI.card begin\n        @h2 \"Card Title\"\n        @UI.my_button {variant = \"secondary\"} \"Click me\"\n    end\nend\n\nMain.display_html(html) #hide","title":"Module-Qualified Components"},{"category":"section","location":"components/#Creating-Component-Macros","page":"Components","text":"Use @deftag to create macro shortcuts for components:\n\nusing HypertextTemplates\nusing HypertextTemplates.Elements\n\n@component function badge(; text, variant = \"primary\", size = \"normal\")\n    size_class = size == \"small\" ? \"badge-sm\" : \"badge-normal\"\n    @span {\n        class = \"badge badge-$variant $size_class\"\n    } $text\nend\n\n# Create a macro for easier use\n@deftag macro badge end\n\n# Now can use as @badge instead of @<badge\nhtml = @render @div begin\n    @h3 begin\n        @text \"Products \"\n        @badge {text = \"New\", variant = \"success\", size = \"small\"}\n    end\n    @p begin\n        @text \"Status: \"\n        @badge {text = \"In Stock\", variant = \"primary\"}\n    end\nend\n\nMain.display_html(html) #hide","title":"Creating Component Macros"},{"category":"section","location":"components/#Component-Patterns","page":"Components","text":"","title":"Component Patterns"},{"category":"section","location":"components/#Container/Presenter-Pattern","page":"Components","text":"Separate logic from presentation:\n\nusing HypertextTemplates\nusing HypertextTemplates.Elements\n\n# Presenter component (pure UI)\n@component function user_list_view(; users)\n    @div {class = \"user-list\"} begin\n        for user in users\n            # Use data attributes for JavaScript interaction\n            @div {class = \"user-item\", \"data-user-id\" := user.id} begin\n                @img {src = user.avatar, alt = user.name, width = 32, height = 32}\n                @span \" \" $(user.name)\n            end\n        end\n    end\nend\n\n@deftag macro user_list_view end\n\n# Example usage with mock data\nusers = [\n    (id = 1, name = \"Alice Johnson\", avatar = \"/avatars/alice.jpg\"),\n    (id = 2, name = \"Bob Smith\", avatar = \"/avatars/bob.jpg\"),\n    (id = 3, name = \"Charlie Brown\", avatar = \"/avatars/charlie.jpg\")\n]\n\nhtml = @render @user_list_view {users}\n\nMain.display_html(html) #hide","title":"Container/Presenter Pattern"},{"category":"section","location":"components/#Compound-Components","page":"Components","text":"Related components that work together:\n\nusing HypertextTemplates\nusing HypertextTemplates.Elements\n\nmodule Tabs\n    using HypertextTemplates\n    using HypertextTemplates.Elements\n\n    @component function container(; active_tab = 1)\n        @div {class = \"tabs\", \"data-active\" := active_tab} begin\n            @__slot__\n        end\n    end\n\n    @deftag macro container end\n\n    @component function list()\n        @ul {class = \"tab-list\", role = \"tablist\"} begin\n            @__slot__\n        end\n    end\n\n    @deftag macro list end\n\n    @component function tab(; index, active = false)\n        @li {role = \"presentation\"} begin\n            @button {\n                role = \"tab\",\n                class = active ? \"tab active\" : \"tab\",\n                \"aria-selected\" := active\n            } begin\n                @__slot__\n            end\n        end\n    end\n\n    @deftag macro tab end\n\n    @component function panels()\n        @div {class = \"tab-panels\"} begin\n            @__slot__\n        end\n    end\n\n    @deftag macro panels end\n\n    @component function panel(; index, active = false)\n        @div {\n            role = \"tabpanel\",\n            class = active ? \"panel active\" : \"panel\",\n            hidden = !active\n        } begin\n            @__slot__\n        end\n    end\n\n    @deftag macro panel end\nend\n\n# Usage\nhtml = @render @Tabs.container {active_tab = 2} begin\n    @Tabs.list begin\n        @Tabs.tab {index = 1, active = false} \"Tab 1\"\n        @Tabs.tab {index = 2, active = true} \"Tab 2\"\n        @Tabs.tab {index = 3, active = false} \"Tab 3\"\n    end\n\n    @Tabs.panels begin\n        @Tabs.panel {index = 1, active = false} begin\n            @p \"Content for tab 1\"\n        end\n        @Tabs.panel {index = 2, active = true} begin\n            @p \"Content for tab 2\"\n        end\n        @Tabs.panel {index = 3, active = false} begin\n            @p \"Content for tab 3\"\n        end\n    end\nend\n\nMain.display_html(html) #hide","title":"Compound Components"},{"category":"section","location":"components/#Safe-Rendering-Pattern","page":"Components","text":"While HypertextTemplates renders directly to IO (making traditional try-catch error boundaries impossible), you can implement safe rendering patterns:\n\nusing HypertextTemplates\nusing HypertextTemplates.Elements\n\n# Helper function to safely access nested data\nsafe_get(obj, field, default=\"N/A\") = try\n    getfield(obj, field)\ncatch\n    default\nend\n\n# Component that handles potentially missing data\n@component function user_card(; user=nothing)\n    @div {class = \"user-card\"} begin\n        if user !== nothing\n            @h3 safe_get(user, :name, \"Unknown User\")\n            @p \"Email: \" safe_get(user, :email)\n            @p \"Role: \" safe_get(user, :role, \"Guest\")\n        else\n            @div {class = \"empty-state\"} begin\n                @p \"No user data available\"\n            end\n        end\n    end\nend\n\n@deftag macro user_card end\n\n# Example with valid user\nuser = (name = \"Alice\", email = \"alice@example.com\", role = \"Admin\")\nhtml1 = @render @user_card {user}\n\nMain.display_html(html1) #hide\n\n# Example with missing user\nhtml2 = @render @user_card {}\n\nMain.display_html(html2) #hide\n\n# Example with partial data\npartial_user = (name = \"Bob\")  # Missing email and role\nhtml3 = @render @user_card {user = partial_user}\n\nMain.display_html(html3) #hide","title":"Safe Rendering Pattern"},{"category":"section","location":"components/#Best-Practices","page":"Components","text":"","title":"Best Practices"},{"category":"section","location":"components/#1.-Keep-Components-Focused","page":"Components","text":"Each component should have a single, clear purpose:\n\nusing HypertextTemplates\nusing HypertextTemplates.Elements\n\n# Good: Focused components\n@component function price_display(; amount, currency = \"USD\")\n    @span {class = \"price\"} $currency \" \" $amount\nend\n\n@deftag macro price_display end\n\n@component function product_card(; product)\n    @div {class = \"product\"} begin\n        @h3 $(product.name)\n        @price_display {amount = product.price, currency = product.currency}\n    end\nend\n\n@deftag macro product_card end\n\n# Example usage\nproduct = (name = \"Laptop\", price = 999.99, currency = \"USD\")\nhtml = @render @product_card {product}\n\nMain.display_html(html) #hide","title":"1. Keep Components Focused"},{"category":"section","location":"components/#2.-Use-Props-for-Configuration","page":"Components","text":"Make components flexible through props:\n\nusing HypertextTemplates\nusing HypertextTemplates.Elements\n\n@component function data_table(;\n    data,\n    columns,\n    striped = true,\n    hoverable = true,\n    bordered = false\n)\n    classes = [\n        \"table\",\n        striped ? \"table-striped\" : nothing,\n        hoverable ? \"table-hover\" : nothing,\n        bordered ? \"table-bordered\" : nothing\n    ] |> x -> filter(!isnothing, x) |> x -> join(x, \" \")\n\n    @table {class = classes} begin\n        @thead begin\n            @tr begin\n                for col in columns\n                    @th $col\n                end\n            end\n        end\n        @tbody begin\n            for row in data\n                @tr begin\n                    for value in row\n                        @td $value\n                    end\n                end\n            end\n        end\n    end\nend\n\n@deftag macro data_table end\n\n# Example usage\ncolumns = [\"Name\", \"Age\", \"City\"]\ndata = [\n    [\"Alice\", 25, \"New York\"],\n    [\"Bob\", 30, \"London\"],\n    [\"Charlie\", 35, \"Tokyo\"]\n]\n\nhtml = @render @data_table {data, columns, striped = true, bordered = true}\n\nMain.display_html(html) #hide","title":"2. Use Props for Configuration"},{"category":"section","location":"components/#3.-Document-Components","page":"Components","text":"Add docstrings to components:\n\n\"\"\"\n    @alert(; type, title, message, dismissible)\n\nDisplay an alert message with optional dismiss button.\n\n# Arguments\n- `type::String = \"info\"`: Alert type (info, warning, error, success)\n- `title::String`: Alert title\n- `message::String`: Alert message body  \n- `dismissible::Bool = false`: Whether alert can be dismissed\n\"\"\"\n@component function alert(; type = \"info\", title, message, dismissible = false)\n    # Implementation\nend","title":"3. Document Components"},{"category":"section","location":"components/#4.-Consider-Performance","page":"Components","text":"For frequently rendered components, optimize:\n\nusing HypertextTemplates\nusing HypertextTemplates.Elements\n\n# Precompute static values\nconst BUTTON_CLASSES = Dict(\n    :primary => \"btn btn-primary\",\n    :secondary => \"btn btn-secondary\",\n    :danger => \"btn btn-danger\"\n)\n\n@component function my_button(; variant = :primary)\n    @button {class = BUTTON_CLASSES[variant]} @__slot__\nend\n\n@deftag macro my_button end\n\n# Example usage\n@render @my_button {variant = :primary} \"Click me\"\n\nMain.display_html(ans) #hide\n\n@render @my_button {variant = :danger} \"Delete\"\nMain.display_html(ans) #hide","title":"4. Consider Performance"},{"category":"section","location":"components/#5.-Error-Handling","page":"Components","text":"Handle edge cases gracefully:\n\nusing HypertextTemplates\nusing HypertextTemplates.Elements\n\n@component function safe_image(; src, alt = \"\", fallback = \"/placeholder.png\")\n    image_src = isempty(src) ? fallback : src\n    @img {src = image_src, alt, onerror = \"this.src='$fallback'\"}\nend\n\n@deftag macro safe_image end\n\n# Example usage\n@render @safe_image {src = \"/user.jpg\", alt = \"User avatar\"}\n\nMain.display_html(ans) #hide\n\n@render @safe_image {src = \"\", alt = \"User avatar\"}\n\nMain.display_html(ans) #hide","title":"5. Error Handling"},{"category":"section","location":"components/#Summary","page":"Components","text":"Components combine reusability, composition through slots, type safety, and flexible rendering to create maintainable templates. Use these patterns to structure your applications effectively.","title":"Summary"},{"category":"section","location":"markdown-integration/#Markdown-Integration","page":"Markdown Integration","text":"HypertextTemplates.jl provides seamless integration with CommonMark.jl, allowing you to create components from Markdown files and mix Markdown content with your templates.","title":"Markdown Integration"},{"category":"section","location":"markdown-integration/#Prerequisites","page":"Markdown Integration","text":"The Markdown integration features are provided through Julia's package extension system, which means they become available automatically when CommonMark.jl is present in your environment. This design keeps HypertextTemplates lightweight for users who don't need Markdown support while providing seamless integration for those who do. Simply adding CommonMark.jl to your project enables all the Markdown-related functionality described in this guide.\n\nusing Pkg\nPkg.add(\"CommonMark\")\n\nThe integration is provided through Julia's package extension system, so features are automatically available when CommonMark.jl is loaded.","title":"Prerequisites"},{"category":"section","location":"markdown-integration/#Inline-Markdown-with-CommonMark","page":"Markdown Integration","text":"","title":"Inline Markdown with CommonMark"},{"category":"section","location":"markdown-integration/#Basic-Usage","page":"Markdown Integration","text":"CommonMark.jl's cm string macro allows you to embed Markdown content directly within your HypertextTemplates components. The macro processes the Markdown at compile time and converts it to HTML, which is then wrapped in a SafeString to preserve the formatting. This approach combines the simplicity of Markdown for content authoring with the power of HypertextTemplates for structure and interactivity, making it ideal for documentation sites, blogs, or any content-heavy application.\n\nusing HypertextTemplates\nusing HypertextTemplates.Elements\nusing CommonMark\n\n@component function article_with_markdown()\n    @article {class = \"prose\"} begin\n        @text CommonMark.cm\"\"\"\n        # Markdown Heading\n        \n        This is a paragraph with **bold** and *italic* text.\n        \n        - List item 1\n        - List item 2\n        \n        > A blockquote\n        \n        ```julia\n        # Code block\n        println(\"Hello from Markdown!\")\n        ```\n        \"\"\"\n    end\nend\n\n# The Markdown is converted to HTML and rendered\nhtml = @render @article_with_markdown","title":"Basic Usage"},{"category":"section","location":"markdown-integration/#Interpolation-in-Markdown","page":"Markdown Integration","text":"CommonMark.jl supports Julia interpolation:\n\n@component function dynamic_markdown(; user_name, item_count)\n    @div {class = \"content\"} begin\n        @text CommonMark.cm\"\"\"\n        # Welcome, $(user_name)!\n        \n        You have **$(item_count)** items in your cart.\n        \n        $(item_count > 0 ? \"Ready to checkout?\" : \"Start shopping!\")\n        \"\"\"\n    end\nend\n\n@render @dynamic_markdown {user_name = \"Alice\", item_count = 3}","title":"Interpolation in Markdown"},{"category":"section","location":"markdown-integration/#Markdown-File-Components","page":"Markdown Integration","text":"The @cm_component macro creates components from Markdown files.","title":"Markdown File Components"},{"category":"section","location":"markdown-integration/#Basic-File-Component","page":"Markdown Integration","text":"The @cm_component macro transforms Markdown files into reusable HypertextTemplates components. This powerful feature allows you to maintain content in Markdown format while seamlessly integrating it into your component-based architecture. The macro reads the specified Markdown file, processes it with CommonMark, and creates a component that can be used just like any other HypertextTemplates component. This is particularly useful for static content pages, documentation, or any scenario where non-technical users need to contribute content.\n\n# Create a component from a Markdown file\n@cm_component about_page() = \"content/about.md\"\n@deftag macro about_page end\n\n# Use it like any other component\n@render @div {class = \"page\"} begin\n    @about_page\nend","title":"Basic File Component"},{"category":"section","location":"markdown-integration/#Components-with-Props","page":"Markdown Integration","text":"Pass props to Markdown files for dynamic content:\n\n# Define component with props\n@cm_component product_description(; name, price) = \"templates/product.md\"\n@deftag macro product_description end\n\n# product.md content:\n# # $(name)\n#\n# **Price:** $$(price)\n\n# Use the component\n@render @product_description {\n    name = \"Premium Widget\",\n    price = 99.99,\n}","title":"Components with Props"},{"category":"section","location":"markdown-integration/#Organizing-Markdown-Components","page":"Markdown Integration","text":"# Use relative paths from your module\n@cm_component header() = joinpath(@__DIR__, \"partials\", \"header.md\")\n@cm_component footer() = joinpath(@__DIR__, \"partials\", \"footer.md\")\n\n# Or organize in a module\nmodule MarkdownComponents\n    using HypertextTemplates\n\n    # Define all Markdown components\n    @cm_component home() = \"content/home.md\"\n    @cm_component about() = \"content/about.md\"\n    @cm_component contact() = \"content/contact.md\"\n\n    # Export tags if you want to use without qualification\n    @deftag export macro home end\n    @deftag export macro about end\n    @deftag export macro contact end\nend\n\n# Use with module qualification\n@render @MarkdownComponents.home\n\n# Or if exported\nusing .MarkdownComponents\n@render @home","title":"Organizing Markdown Components"},{"category":"section","location":"markdown-integration/#Live-Reloading-with-Revise.jl","page":"Markdown Integration","text":"When Revise.jl is available, Markdown file components automatically reload when the file changes.","title":"Live Reloading with Revise.jl"},{"category":"section","location":"markdown-integration/#Setup","page":"Markdown Integration","text":"using Revise\nusing HypertextTemplates\nusing CommonMark\n\n# Define a Markdown component\n@cm_component live_content() = \"content/live.md\"\n\n# Edit content/live.md in your editor\n# Changes are reflected immediately when you re-render\n@render @live_content","title":"Setup"},{"category":"section","location":"markdown-integration/#Advanced-Markdown-Patterns","page":"Markdown Integration","text":"","title":"Advanced Markdown Patterns"},{"category":"section","location":"markdown-integration/#Markdown-Layout-Components","page":"Markdown Integration","text":"Create layout components that accept Markdown content:\n\n@component function markdown_layout(; title, markdown_file)\n    @html begin\n        @head begin\n            @title $title\n            @style \"\"\"\n            .prose { max-width: 65ch; margin: 0 auto; }\n            .prose h1 { color: #333; }\n            .prose code { background: #f4f4f4; padding: 0.2em; }\n            \"\"\"\n        end\n        @body begin\n            @div {class = \"prose\"} begin\n                @<markdown_file\n            end\n        end\n    end\nend\n\n# Use with Markdown components\n@cm_component intro() = \"intro.md\"\n@render @markdown_layout {title = \"Introduction\", markdown_file = intro}","title":"Markdown Layout Components"},{"category":"section","location":"markdown-integration/#Mixed-Content","page":"Markdown Integration","text":"Combine Markdown with HTML components:\n\n@component function blog_post(; meta, content_file)\n    @article begin\n        @header begin\n            @h1 $meta.title\n            @p {class = \"meta\"} begin\n                \"By \" @strong $meta.author \" on \" @time $meta.date\n            end\n        end\n\n        @div {class = \"content prose\"} begin\n            @<content_file  # Markdown component\n        end\n\n        @footer begin\n            @nav begin\n                if !isnothing(meta.prev)\n                    @a {href = meta.prev.url} \"← \" $meta.prev.title\n                end\n                if !isnothing(meta.next)\n                    @a {href = meta.next.url} $meta.next.title \" →\"\n                end\n            end\n        end\n    end\nend","title":"Mixed Content"},{"category":"section","location":"markdown-integration/#Dynamic-Markdown-Loading","page":"Markdown Integration","text":"Load Markdown content dynamically:\n\n@component function dynamic_docs(; path)\n    # Validate path for security\n    safe_path = validate_doc_path(path)\n\n    if isfile(safe_path)\n        # Read and render Markdown\n        content = read(safe_path, String)\n        html = CommonMark.html(content)\n        @div {class = \"documentation\"} $(SafeString(html))\n    else\n        @div {class = \"error\"} begin\n            @h1 \"404 - Page Not Found\"\n            @p \"The requested documentation page does not exist.\"\n        end\n    end\nend\n\nfunction validate_doc_path(path)\n    # Security: Ensure path is within docs directory\n    cleaned = normpath(joinpath(\"docs\", path))\n    if startswith(cleaned, \"docs/\") && endswith(cleaned, \".md\")\n        return cleaned\n    else\n        return \"\"\n    end\nend","title":"Dynamic Markdown Loading"},{"category":"section","location":"markdown-integration/#CommonMark-Configuration","page":"Markdown Integration","text":"","title":"CommonMark Configuration"},{"category":"section","location":"markdown-integration/#Custom-Rendering","page":"Markdown Integration","text":"Configure CommonMark parsing and rendering:\n\nusing CommonMark\n\n# Create custom parser with extensions\nparser = Parser()\nenable!(parser, DollarMathRule())\nenable!(parser, TableRule())\nenable!(parser, FootnoteRule())\n\n@component function enhanced_markdown(; content)\n    # Parse with custom settings\n    ast = parser(content)\n\n    # Render to HTML\n    html = html(ast)\n\n    @div {class = \"enhanced-content\"} $(SafeString(html))\nend","title":"Custom Rendering"},{"category":"section","location":"markdown-integration/#Best-Practices","page":"Markdown Integration","text":"","title":"Best Practices"},{"category":"section","location":"markdown-integration/#1.-File-Organization","page":"Markdown Integration","text":"Structure your Markdown files logically:\n\nproject/\n├── src/\n│   └── components.jl\n├── content/\n│   ├── pages/\n│   │   ├── home.md\n│   │   └── about.md\n│   ├── blog/\n│   │   └── posts/\n│   └── docs/\n│       ├── getting-started.md\n│       └── api-reference.md","title":"1. File Organization"},{"category":"section","location":"markdown-integration/#2.-Props-Documentation","page":"Markdown Integration","text":"Document props in your Markdown files:\n\n<!-- product-template.md -->\n<!-- Props: name (String), price (Float64), description (String) -->\n\n# $(name)\n\n**Price:** $$(price)\n\n$(description)","title":"2. Props Documentation"},{"category":"section","location":"markdown-integration/#3.-Performance","page":"Markdown Integration","text":"Cache parsed Markdown for frequently accessed content:\n\nconst MARKDOWN_CACHE = Dict{String, String}()\n\n@component function cached_markdown(; file)\n    html = get!(MARKDOWN_CACHE, file) do\n        content = read(file, String)\n        CommonMark.html(content)\n    end\n\n    @div {class = \"cached-content\"} $(SafeString(html))\nend","title":"3. Performance"},{"category":"section","location":"markdown-integration/#Summary","page":"Markdown Integration","text":"Markdown integration in HypertextTemplates.jl provides:\n\nInline Markdown with the CommonMark.jl cm string macro\nFile-based components with @cm_component\nFull interpolation support in Markdown content\nLive reloading with Revise.jl integration\n\nThis integration makes it easy to build content-heavy sites while maintaining the full power of HypertextTemplates.jl's component system.","title":"Summary"},{"category":"section","location":"api/#API-Reference","page":"API Reference","text":"","title":"API Reference"},{"category":"section","location":"api/#Public","page":"API Reference","text":"The public API consists of all exported functions, macros, and types that are intended for end users. These APIs are stable and follow semantic versioning - breaking changes will only occur in major version updates. The public API includes the core @render macro, component definition utilities like @component and @deftag, security features like SafeString, and all the HTML element macros available through HypertextTemplates.Elements. These are the building blocks you'll use to create templates and components in your applications.","title":"Public"},{"category":"section","location":"api/#Internal","page":"API Reference","text":"The internal API includes implementation details, helper functions, and low-level utilities that power HypertextTemplates but are not intended for direct use. These APIs may change between minor versions without notice as we optimize performance or refactor internals. While these functions are documented for contributors and those needing to understand the implementation, you should avoid depending on them in production code. If you find yourself needing internal functionality, please open an issue - it might indicate a gap in the public API that we should address.","title":"Internal"},{"category":"module","location":"api/#HypertextTemplates.HypertextTemplates","page":"API Reference","text":"HypertextTemplates\n\nA hypertext templating DSL for Julia that allows writing HTML using native Julia syntax.\n\nHypertextTemplates provides a macro-based DSL where all HTML elements are exposed as macros (e.g., @div, @p). It uses a special {} syntax for attributes that mimics NamedTuples, allowing natural integration of Julia control flow directly in templates.\n\nKey Features\n\nZero-allocation rendering: Direct IO streaming without intermediate DOM\nComponent system: Reusable components with props and slots\nAuto-escaping: Automatic HTML escaping for security (bypass with SafeString)\nStreaming support: Efficient chunked rendering for large documents\nMarkdown integration: Render Markdown files as components (requires CommonMark.jl)\n\nBasic Usage\n\nusing HypertextTemplates, HypertextTemplates.Elements\n\n# Simple rendering\n@render @div {class = \"greeting\"} \"Hello, World!\"\n\n# Components with slots\n@component function card(; title)\n    @div {class = \"card\"} begin\n        @h2 $title\n        @div {class = \"body\"} @__slot__\n    end\nend\n\nMain Exports\n\n@render: Render templates to strings or IO\n@component: Define reusable components\n@deftag: Create macro shortcuts for components\nSafeString: Mark content as pre-escaped HTML\nStreamingRender: Iterator for chunked rendering\n@<: Dynamic component/element rendering\n\nSee the documentation for detailed examples and advanced features.\n\n\n\n\n\n","title":"HypertextTemplates.HypertextTemplates"},{"category":"type","location":"api/#HypertextTemplates.SafeString","page":"API Reference","text":"SafeString(str::String)\n\nA string wrapper that bypasses automatic HTML escaping.\n\nBy default, all string content is HTML-escaped to prevent XSS attacks. SafeString marks content as pre-escaped or trusted HTML that should be rendered as-is.\n\nwarning: Security Risk\nOnly use SafeString with content you trust completely. Never wrap user input directly with SafeString without proper sanitization. This can lead to XSS vulnerabilities.\n\nArguments\n\nstr::String: The HTML string to mark as safe\n\nExamples\n\njulia> using HypertextTemplates, HypertextTemplates.Elements\n\njulia> # Normal strings are escaped\n       @render @div \"<b>Bold</b>\"\n\"<div>&lt;b&gt;Bold&lt;/b&gt;</div>\"\n\njulia> # SafeString content is not escaped\n       @render @div $(SafeString(\"<b>Bold</b>\"))\n\"<div><b>Bold</b></div>\"\n\njulia> # Common use case: pre-rendered markdown\n       markdown_html = \"<p>Already <em>escaped</em> content</p>\";\n\njulia> @render @article $(SafeString(markdown_html))\n\"<article><p>Already <em>escaped</em> content</p></article>\"\n\nSecurity best practices\n\n# GOOD: Content from trusted sources\nhtml = markdown_to_html(user_content)  # Markdown processor escapes content\n@render @div SafeString(html)\n\n# GOOD: Your own HTML generation\nsafe_html = \"<span class=\"highlight\">Important</span>\"\n@render @div SafeString(safe_html)\n\n# BAD: Never do this with user input!\nuser_input = get_user_input()\n@render @div SafeString(user_input)  # DANGER: XSS vulnerability!\n\nSee also: @render, escape_html, @esc_str\n\n\n\n\n\n","title":"HypertextTemplates.SafeString"},{"category":"type","location":"api/#HypertextTemplates.StreamingRender","page":"API Reference","text":"StreamingRender(func; kwargs...)\nStreamingRender(; kwargs...) do io\n    # render content\nend\n\nCreate an iterator for streaming template rendering.\n\nStreamingRender enables efficient rendering of large templates by yielding chunks of output as they become available. This is particularly useful for:\n\nHTTP streaming responses\nLarge documents that would consume too much memory if rendered at once\nProgressive rendering where content appears as it's generated\n\nThe function uses intelligent micro-batching: large writes (≥64 bytes) are sent immediately for low latency, while smaller writes are batched for efficiency.\n\nArguments\n\nfunc: Function that takes an io argument to pass to @render\n\nKeywords\n\nbuffer_size::Int=32: Number of chunks the channel can buffer before blocking\nchunk_size::Int=4096: Legacy parameter (kept for compatibility, no longer used)\nimmediate_threshold::Int=64: Bytes above which writes bypass buffering for low latency\n\nExamples\n\njulia> using HypertextTemplates, HypertextTemplates.Elements\n\njulia> # Collect all chunks (for demonstration)\n       chunks = String[];\n\njulia> for chunk in StreamingRender() do io\n           @render io @div begin\n               @h1 \"Header\"\n               @p \"Content\"\n           end\n       end\n           push!(chunks, String(chunk))\n       end\n\njulia> join(chunks)\n\"<div><h1>Header</h1><p>Content</p></div>\"\n\nHTTP streaming example\n\nusing HTTP\nusing HypertextTemplates, HypertextTemplates.Elements\n\nfunction handle_request(req)\n    HTTP.Response(200, [\"Content-Type\" => \"text/html\"]) do io\n        for chunk in StreamingRender() do render_io\n            @render render_io @html begin\n                @head @title \"Streaming Page\"\n                @body begin\n                    @h1 \"Live Data\"\n                    for i in 1:1000\n                        @div \"Item $i\"\n                    end\n                end\n            end\n        end\n            write(io, chunk)\n        end\n    end\nend\n\nProgressive rendering\n\n# Stream data as it becomes available\nfor chunk in StreamingRender() do io\n    @render io @div begin\n        @h1 \"Results\"\n        for result in fetch_results_lazily()\n            @article begin\n                @h2 result.title\n                @p result.content\n            end\n        end\n    end\nend\n    # Send chunk to client immediately\n    write(client_connection, chunk)\n    flush(client_connection)\nend\n\nSee also: @render, MicroBatchWriter\n\n\n\n\n\n","title":"HypertextTemplates.StreamingRender"},{"category":"macro","location":"api/#HypertextTemplates.@<-Tuple{Any, Vararg{Any}}","page":"API Reference","text":"@<component_or_element\n@<component_or_element children...\n@<component_or_element {props...}\n@<component_or_element {props...} children...\n\nDynamically render a component or element from a variable.\n\nThe @< macro enables dynamic component selection, where the component or element to render is determined at runtime. This is useful for polymorphic rendering, component mappings, and conditional component selection.\n\nArguments\n\ncomponent_or_element: A variable containing a component function or element\nprops...: Optional properties in {} syntax\nchildren...: Optional child content\n\nExamples\n\njulia> using HypertextTemplates, HypertextTemplates.Elements\n\njulia> # Dynamic element selection\n       tag = Elements.div\n       @render @<tag {class = \"dynamic\"} \"Content\"\n\"<div class=\\\"dynamic\\\">Content</div>\"\n\njulia> # Change element at runtime\n       tag = span\n       @render @<tag {class = \"dynamic\"} \"Content\"\n\"<span class=\\\"dynamic\\\">Content</span>\"\n\nDynamic component selection\n\njulia> using HypertextTemplates, HypertextTemplates.Elements\n\njulia> # Define components\n       @component function info_box(; message)\n           @div {class = \"info\"} @p $message\n       end;\n\njulia> @component function error_box(; message)\n           @div {class = \"error\"} @strong $message\n       end;\n\njulia> # Select component based on condition\n       function render_message(type, message)\n           component = type == :error ? error_box : info_box\n           @render @<component {message}\n       end\nrender_message (generic function with 1 method)\n\njulia> render_message(:info, \"All good!\")\n\"<div class=\\\"info\\\"><p>All good!</p></div>\"\n\njulia> render_message(:error, \"Something went wrong!\")\n\"<div class=\\\"error\\\"><strong>Something went wrong!</strong></div>\"\n\nWith slots\n\njulia> using HypertextTemplates, HypertextTemplates.Elements\n\njulia> @component function wrapper(; variant = \"default\")\n           @div {class = \"wrapper-$variant\"} @__slot__\n       end;\n\njulia> # Dynamic wrapper\n       w = wrapper\n       @render @<w {variant = \"special\"} begin\n           @h1 \"Wrapped content\"\n       end\n\"<div class=\\\"wrapper-special\\\"><h1>Wrapped content</h1></div>\"\n\nSee also: @component, @deftag\n\n\n\n\n\n","title":"HypertextTemplates.@<"},{"category":"macro","location":"api/#HypertextTemplates.@__once__-Tuple{Any}","page":"API Reference","text":"@__once__ begin\n    # content to render once\nend\n\nRender content only once per @render call.\n\nThe @__once__ macro ensures that its content is rendered only once, even if the containing component is used multiple times within the same render tree. This is essential for including CSS, JavaScript, or other resources that should not be duplicated.\n\nCommon use cases\n\nCSS styles that should appear once\nJavaScript libraries and initialization code\nMeta tags or link elements in components\nAny content that would cause issues if duplicated\n\nExamples\n\njulia> using HypertextTemplates, HypertextTemplates.Elements\n\njulia> @component function button_with_styles(; text, variant = \"primary\")\n           @__once__ begin\n               @style \"\"\"\n               .btn { padding: 10px; border: none; cursor: pointer; }\n               .btn-primary { background: blue; color: white; }\n               .btn-danger { background: red; color: white; }\n               \"\"\"\n           end\n           @button {class = \"btn btn-$variant\"} $text\n       end;\n\njulia> @deftag macro button_with_styles end\n@button_with_styles (macro with 1 method)\n\nJavaScript dependencies\n\njulia> using HypertextTemplates, HypertextTemplates.Elements\n\njulia> @component function chart(; data)\n           @__once__ begin\n               @script {src = \"https://cdn.plot.ly/plotly-latest.min.js\"}\n           end\n           @div {id = \"chart-$(hash(data))\"} begin\n               @script \"\"\"\n               Plotly.newPlot('chart-$(hash(data))', $(data));\n               \"\"\"\n           end\n       end;\n\njulia> @deftag macro chart end\n@chart (macro with 1 method)\n\nScope behavior\n\nEach @render call maintains its own set of rendered once-blocks:\n\njulia> using HypertextTemplates, HypertextTemplates.Elements\n\njulia> @component function with_header()\n           @__once__ @h1 \"Page Header\"\n           @p \"Content\"\n       end;\n\njulia> @deftag macro with_header end\n@with_header (macro with 1 method)\n\njulia> # First render includes the header\n       @render @with_header\n\"<h1>Page Header</h1><p>Content</p>\"\n\njulia> # Second render also includes it (different @render call)\n       @render @with_header\n\"<h1>Page Header</h1><p>Content</p>\"\n\nSee also: @component, @render\n\n\n\n\n\n","title":"HypertextTemplates.@__once__"},{"category":"macro","location":"api/#HypertextTemplates.@__slot__","page":"API Reference","text":"@__slot__ [name]\n\nDefine a content slot within a component.\n\nSlots enable content projection - allowing parent components to pass content into specific locations within child components. This is essential for creating flexible, composable components.\n\nArguments\n\nname: Optional slot name. If omitted, creates the default slot.\n\nDefault slot\n\nThe default slot (no name) receives all content passed to the component that isn't assigned to a named slot.\n\njulia> using HypertextTemplates, HypertextTemplates.Elements\n\njulia> @component function card(; title)\n           @div {class = \"card\"} begin\n               @h2 $title\n               @div {class = \"content\"} @__slot__\n           end\n       end;\n\njulia> @deftag macro card end\n@card (macro with 1 method)\n\njulia> @render @card {title = \"Welcome\"} begin\n           @p \"This goes into the default slot\"\n           @p \"So does this\"\n       end\n\"<div class=\\\"card\\\"><h2>Welcome</h2><div class=\\\"content\\\"><p>This goes into the default slot</p><p>So does this</p></div></div>\"\n\nNamed slots\n\nNamed slots receive only content explicitly assigned to them using name := content syntax.\n\njulia> using HypertextTemplates, HypertextTemplates.Elements\n\njulia> @component function modal(; title = \"\")\n           @div {class = \"modal\"} begin\n               @header begin\n                   @h2 $title\n                   @__slot__ header_actions\n               end\n               @div {class = \"body\"} @__slot__\n               @footer @__slot__ footer\n           end\n       end;\n\njulia> @deftag macro modal end\n@modal (macro with 1 method)\n\njulia> @render @modal {title = \"Confirm\"} begin\n           # Default slot content\n           @p \"Are you sure?\"\n           # Named slot content\n           header_actions := @button {class = \"close\"} \"×\"\n           footer := begin\n               @button \"Cancel\"\n               @button {class = \"primary\"} \"OK\"\n           end\n       end\n\"<div class=\\\"modal\\\"><header><h2>Confirm</h2><button class=\\\"close\\\">×</button></header><div class=\\\"body\\\"><p>Are you sure?</p></div><footer><button>Cancel</button><button class=\\\"primary\\\">OK</button></footer></div>\"\n\nSee also: @component\n\n\n\n\n\n","title":"HypertextTemplates.@__slot__"},{"category":"macro","location":"api/#HypertextTemplates.@cm_component-Tuple{Any}","page":"API Reference","text":"@cm_component component_name(; props...) = \"file_name.md\"\n\nCreate a component from a Markdown file.\n\nThis macro creates a component that renders Markdown content from a file. The Markdown is parsed using CommonMark.jl and can include interpolated values using $variable syntax.\n\nnote: Note\nThis feature requires CommonMark.jl to be installed as it's provided via Julia's package extension mechanism.\n\nArguments\n\ncomponent_name: Name for the component function\nprops...: Optional keyword arguments that can be interpolated in the Markdown\nfile_name.md: Path to the Markdown file (relative to the current file)\n\nFeatures\n\nInterpolation: Use $prop_name in Markdown to insert prop values\nLive reload: With Revise.jl, changes to the Markdown file auto-update\nCompile-time parsing: Without Revise.jl, Markdown is parsed at compile time for performance\n\nExamples\n\nBasic usage\n\n# In article.md:\n# # $title\n# \n# By $author on $date\n# \n# $content\n\n# In your Julia code:\nusing HypertextTemplates, HypertextTemplates.Elements\nusing CommonMark\n\n@cm_component article(; title, author, date, content) = \"article.md\"\n@deftag macro article end\n\n@render @article {\n    title = \"Hello World\",\n    author = \"Jane Doe\",\n    date = \"2024-01-15\",\n    content = \"This is my first post!\"\n}\n\nDirectory structure\n\n# components/header.md contains:\n# # $site_name\n# \n# *$tagline*\n\n# In components/components.jl:\n@cm_component header(; site_name, tagline = \"Welcome\") = \"header.md\"\n\n# Path is relative to the file containing @cm_component\n\nWith default values\n\n@cm_component footer(; copyright_year = 2024, company = \"Acme Corp\") = \"footer.md\"\n@deftag macro footer end\n\n# Uses defaults\n@render @footer\n\n# Override defaults\n@render @footer {copyright_year = 2025}\n\nComplex content interpolation\n\n# In template.md:\n# # Product: $name\n# \n# Price: $$$price\n# \n# $description\n\n@cm_component product_card(; name, price, description) = \"template.md\"\n@deftag macro product_card end\n\n@render @product_card {\n    name = \"Widget\",\n    price = 19.99,\n    description = \"A **fantastic** widget with _many_ features!\"\n}\n\ntip: Development workflow\nWhen using Revise.jl, you can edit the Markdown file and see changes immediately without restarting Julia or redefining the component.\n\nSee also: @component, SafeString\n\n\n\n\n\n","title":"HypertextTemplates.@cm_component"},{"category":"macro","location":"api/#HypertextTemplates.@component-Tuple{Any}","page":"API Reference","text":"@component function component_name(; properties...)\n    # template body\nend\n\nDefine a reusable component function.\n\nComponents are functions that return template content and can accept properties as keyword arguments. They enable code reuse and composition in templates.\n\nAfter defining a component, use @deftag to create a convenient macro for using it like a regular HTML element.\n\nArguments\n\ncomponent_name: The name of the component function\nproperties...: Keyword arguments that become the component's props\n\nExamples\n\njulia> using HypertextTemplates, HypertextTemplates.Elements\n\njulia> @component function greeting(; name = \"World\")\n           @h1 \"Hello, \" $name \"!\"\n       end\ngreeting (generic function with 1 method)\n\njulia> @deftag macro greeting end\n@greeting (macro with 1 method)\n\njulia> @render @greeting {name = \"Julia\"}\n\"<h1>Hello, Julia!</h1>\"\n\njulia> @render @greeting  # Uses default value\n\"<h1>Hello, World!</h1>\"\n\nComponents with slots\n\njulia> using HypertextTemplates, HypertextTemplates.Elements\n\njulia> @component function card(; title)\n           @div {class = \"card\"} begin\n               @h2 $title\n               @div {class = \"body\"} @__slot__\n           end\n       end\ncard (generic function with 1 method)\n\njulia> @deftag macro card end\n@card (macro with 1 method)\n\njulia> @render @card {title = \"Info\"} begin\n           @p \"Card content goes here\"\n       end\n\"<div class=\\\"card\\\"><h2>Info</h2><div class=\\\"body\\\"><p>Card content goes here</p></div></div>\"\n\nTyped props for safety\n\njulia> using HypertextTemplates, HypertextTemplates.Elements\n\njulia> @component function price(; amount::Number, currency::String = \"USD\")\n           @span {class = \"price\"} $currency \" \" $(round(amount, digits=2))\n       end\nprice (generic function with 1 method)\n\njulia> @deftag macro price end\n@price (macro with 1 method)\n\njulia> @render @price {amount = 19.999}\n\"<span class=\\\"price\\\">USD 20.0</span>\"\n\nSee also: @deftag, @__slot__, @render\n\n\n\n\n\n","title":"HypertextTemplates.@component"},{"category":"macro","location":"api/#HypertextTemplates.@deftag-Tuple{Any}","page":"API Reference","text":"@deftag macro name end\n@deftag name\n\nCreate a macro shortcut for using a component or element.\n\nAfter defining a component with @component, use @deftag to create a convenient macro that allows using the component like an HTML element.\n\nThe macro name end syntax is preferred as it allows the LSP to correctly track the macro definition location.\n\nArguments\n\nname: Symbol name of the component/element to create a macro for\n\nExamples\n\njulia> using HypertextTemplates, HypertextTemplates.Elements\n\njulia> # Define a component\n       @component function alert(; type = \"info\", dismissible = false)\n           @div {class = \"alert alert-$type\"} begin\n               @__slot__\n               if dismissible\n                   @button {class = \"close\"} \"×\"\n               end\n           end\n       end\nalert (generic function with 1 method)\n\njulia> # Create macro (preferred syntax for LSP support)\n       @deftag macro alert end\n@alert (macro with 1 method)\n\njulia> # Now use like an HTML element\n       @render @alert {type = \"warning\"} \"Watch out!\"\n\"<div class=\\\"alert alert-warning\\\">Watch out!</div>\"\n\njulia> # Alternative syntax (works but no LSP support)\n       @component function message(; text)\n           @p {class = \"message\"} $text\n       end\nmessage (generic function with 1 method)\n\njulia> @deftag message\n@message (macro with 1 method)\n\njulia> @render @message {text = \"Hello\"}\n\"<p class=\\\"message\\\">Hello</p>\"\n\nCustom elements\n\njulia> using HypertextTemplates, HypertextTemplates.Elements\n\njulia> # Define a custom HTML element\n       @element \"my-widget\" my_widget\n\njulia> @deftag macro my_widget end\n@my_widget (macro with 1 method)\n\njulia> @render @my_widget {id = \"w1\"} \"Custom element\"\n\"<my-widget id=\\\"w1\\\">Custom element</my-widget>\"\n\nSee also: @component, @element, @<\n\n\n\n\n\n","title":"HypertextTemplates.@deftag"},{"category":"macro","location":"api/#HypertextTemplates.@element","page":"API Reference","text":"@element html_tag_name [julia_name]\n\nDefine a custom HTML element.\n\nCreates a new HTML element that can be used with HypertextTemplates' macro syntax. This is useful for custom elements, web components, or HTML elements not included in the default set.\n\nArguments\n\nhtml_tag_name: The HTML tag name as it will appear in output (e.g., \"my-element\")\njulia_name: Optional Julia identifier name (defaults to html_tag_name with invalid characters replaced)\n\nExamples\n\njulia> using HypertextTemplates\n\njulia> # Define a custom element\n       @element \"my-widget\" my_widget\n\njulia> # Use with @deftag for macro syntax\n       @deftag macro my_widget end\n@my_widget (macro with 1 method)\n\njulia> @render @my_widget {id = \"w1\", class = \"custom\"} \"Widget content\"\n\"<my-widget id=\\\"w1\\\" class=\\\"custom\\\">Widget content</my-widget>\"\n\nWeb Components\n\njulia> using HypertextTemplates\n\njulia> # Define web component elements\n       @element \"ion-button\" ion_button\n\njulia> @element \"ion-icon\" ion_icon\n\njulia> @deftag macro ion_button end\n@ion_button (macro with 1 method)\n\njulia> @deftag macro ion_icon end\n@ion_icon (macro with 1 method)\n\njulia> @render @ion_button {color = \"primary\", expand = \"block\"} begin\n           @ion_icon {name = \"save-outline\", slot = \"start\"}\n           \"Save\"\n       end\n\"<ion-button color=\\\"primary\\\" expand=\\\"block\\\"><ion-icon name=\\\"save-outline\\\" slot=\\\"start\\\"></ion-icon>Save</ion-button>\"\n\nSee also: @deftag, @component\n\n\n\n\n\n","title":"HypertextTemplates.@element"},{"category":"macro","location":"api/#HypertextTemplates.@esc_str-Tuple{Any}","page":"API Reference","text":"@esc_str\n\nEscape HTML at compile time and return a SafeString.\n\nThis string macro performs HTML escaping during macro expansion rather than at runtime, providing better performance for static content that needs escaping.\n\nThe resulting SafeString will not be escaped again during rendering.\n\nSee also: SafeString, escape_html\n\n\n\n\n\n","title":"HypertextTemplates.@esc_str"},{"category":"macro","location":"api/#HypertextTemplates.@render-Tuple{Any, Any}","page":"API Reference","text":"@render [destination] dom\n\nRender a template to the given destination.\n\nIf no destination is provided, renders to a String and returns it. The destination  can be any IO object (e.g., stdout, IOBuffer, file handle) or a type like  String or Vector{UInt8}.\n\nThis macro is only needed for rendering the root of the DOM tree, not for the output of each individual component that is defined.\n\nArguments\n\ndestination: Optional IO object or type to render to (default: String)\ndom: The template expression to render\n\nExamples\n\njulia> using HypertextTemplates, HypertextTemplates.Elements\n\njulia> @render @div \"Hello, World!\"\n\"<div>Hello, World!</div>\"\n\njulia> buffer = IOBuffer();\n\njulia> @render buffer @span {class = \"greeting\"} \"Hi!\";\n\njulia> String(take!(buffer))\n\"<span class=\\\"greeting\\\">Hi!</span>\"\n\njulia> @render Vector{UInt8} @p \"Binary output\"\n20-element Vector{UInt8}:\n 0x3c\n 0x70\n 0x3e\n 0x42\n 0x69\n 0x6e\n 0x61\n 0x72\n 0x79\n 0x20\n 0x6f\n 0x75\n 0x74\n 0x70\n 0x75\n 0x74\n 0x3c\n 0x2f\n 0x70\n 0x3e\n\nRendering to files\n\nopen(\"output.html\", \"w\") do file\n    @render file @html begin\n        @head @title \"My Page\"\n        @body @h1 \"Hello!\"\n    end\nend\n\nSee also: StreamingRender, @component\n\n\n\n\n\n","title":"HypertextTemplates.@render"},{"category":"macro","location":"api/#HypertextTemplates.@text-Tuple","page":"API Reference","text":"@text content...\n\nExplicitly render content as text within templates.\n\nThe @text macro explicitly marks content for text rendering with HTML escaping. It is rarely needed directly since the $ interpolation syntax provides the same functionality more concisely.\n\nText content is automatically HTML-escaped unless wrapped in SafeString.\n\nArguments\n\ncontent...: One or more values to render as text\n\nExamples\n\njulia> using HypertextTemplates, HypertextTemplates.Elements\n\njulia> # HTML is escaped by default\n       @render @div @text \"<script>alert('XSS')</script>\"\n\"<div>&lt;script&gt;alert('XSS')&lt;/script&gt;</div>\"\n\njulia> # Mix with elements\n       @render @div begin\n           @h1 \"Title\"\n           @text \"Some text content\"\n           @p \"In a paragraph\"\n       end\n\"<div><h1>Title</h1>Some text content<p>In a paragraph</p></div>\"\n\ntip: Tip\nThe $ interpolation syntax is preferred over @text in most cases:# Preferred\n@div \"Count: \" $count\n\n# Equivalent but verbose\n@div \"Count: \" @text count\n\nSee also: SafeString, escape_html\n\n\n\n\n\n","title":"HypertextTemplates.@text"},{"category":"module","location":"api/#HypertextTemplates.Elements","page":"API Reference","text":"HypertextTemplates.Elements\n\nStandard HTML elements for use with HypertextTemplates.\n\nThis module provides all standard HTML5 elements as both functions and macros. Each element can be used either as a macro (e.g., @div) or accessed as a function (e.g., Elements.div).\n\nUsage\n\nusing HypertextTemplates, HypertextTemplates.Elements\n\n# Use elements as macros\n@render @div {class = \"container\"} begin\n    @h1 \"Title\"\n    @p \"Content\"\nend\n\n# Or access them as values for dynamic rendering\nelement = rand() > 0.5 ? Elements.div : Elements.span\n@render @<element \"Dynamic content\"\n\nAvailable Elements\n\nAll standard HTML5 elements are available, including:\n\nDocument structure: html, head, body, div, span\nText content: p, h1-h6, blockquote, pre\nForms: form, input, textarea, select, button\nMedia: img, video, audio, canvas\nTables: table, tr, td, th\nAnd many more...\n\nSpecial Behavior\n\nThe @html element automatically includes <!DOCTYPE html>\nVoid elements (like br, img, input) are self-closing\n\n\n\n\n\n","title":"HypertextTemplates.Elements"},{"category":"type","location":"api/#HypertextTemplates.MicroBatchWriter","page":"API Reference","text":"MicroBatchWriter <: IO\n\nInternal writer that implements the micro-batching strategy. It acts as an intelligent buffer between the rendering code and the Channel, making decisions about when to send data based on size and time thresholds.\n\nThe writer follows these rules:\n\nLarge writes (≥ immediate_threshold) bypass buffering entirely\nSmall writes accumulate in a buffer until a threshold is reached\nA timer ensures buffered data is flushed within maxbuffertime\n\n\n\n\n\n","title":"HypertextTemplates.MicroBatchWriter"},{"category":"method","location":"api/#HypertextTemplates.TemplateFileLookup-Tuple{Any}","page":"API Reference","text":"TemplateFileLookup(handler)\n\nThis is a developer tool that can be added to an HTTP handler stack to allow the user to open the template file in their default editor by holding down the Ctrl key and clicking on the rendered template. This is useful for debugging navigating the template files instead of having to manually search through a codebase for the template file that renders a given item within a page.\n\nHTTP.serve(router |> TemplateFileLookup, host, port)\n\nAlways add the TemplateFileLookup handler after the other handlers, since it needs to inject a script into the response to listen for clicks on the rendered template.\n\n\n\n\n\n","title":"HypertextTemplates.TemplateFileLookup"},{"category":"method","location":"api/#HypertextTemplates.create_flush_timer-Tuple{HypertextTemplates.MicroBatchWriter}","page":"API Reference","text":"create_flush_timer(writer::MicroBatchWriter)\n\nCreate a Timer that periodically flushes the writer's buffer if data is present and enough time has passed since the last write.\n\nThe timer is crucial for bounded latency - without it, small writes that don't trigger size-based flushing could sit in the buffer indefinitely. This ensures that even a single character written will appear within maxbuffertime.\n\n\n\n\n\n","title":"HypertextTemplates.create_flush_timer"},{"category":"method","location":"api/#HypertextTemplates.escape_attr-Tuple{IO, AbstractString}","page":"API Reference","text":"escape_attr(io::IO, value)\n\nWrite HTML attribute-escaped content to an IO stream.\n\nThis function escapes characters that have special meaning in HTML attributes, providing more comprehensive escaping than escape_html. It is automatically called for all attribute values unless wrapped in SafeString.\n\nEscaped characters\n\n& → &amp;\n< → &lt;\n> → &gt;\n\" → &quot;\n' → &#39;\n\nArguments\n\nio::IO: The output stream to write to\nvalue: The attribute value to escape (converted to string if not already)\n\nnote: Note\nThis function provides defense-in-depth but cannot prevent all attribute-based attacks. Always validate URLs and other sensitive attribute values at the application level.\n\nSee also: escape_html, SafeString\n\n\n\n\n\n","title":"HypertextTemplates.escape_attr"},{"category":"method","location":"api/#HypertextTemplates.escape_html-Tuple{IO, AbstractString}","page":"API Reference","text":"escape_html(io::IO, value)\n\nWrite HTML-escaped content to an IO stream.\n\nThis function escapes HTML special characters to prevent XSS attacks when rendering user content. It is automatically called by HypertextTemplates for all string content unless wrapped in SafeString.\n\nEscaped characters\n\n& → &amp;\n< → &lt;\n> → &gt;\n\nArguments\n\nio::IO: The output stream to write to\nvalue: The content to escape (converted to string if not already)\n\nExamples\n\njulia> using HypertextTemplates\n\njulia> io = IOBuffer();\n\njulia> HypertextTemplates.escape_html(io, \"Hello <script>alert('XSS')</script>\")\n\njulia> String(take!(io))\n\"Hello &lt;script&gt;alert('XSS')&lt;/script&gt;\"\n\njulia> # SafeString content is not escaped\n       io = IOBuffer();\n\njulia> HypertextTemplates.escape_html(io, SafeString(\"<b>Bold</b>\"))\n\njulia> String(take!(io))\n\"<b>Bold</b>\"\n\nSee also: escape_attr, SafeString, @esc_str\n\n\n\n\n\n","title":"HypertextTemplates.escape_html"},{"category":"method","location":"api/#HypertextTemplates.render-Tuple{Function}","page":"API Reference","text":"render([dst], component; properties...)\n\nRender the component with the given properties to the optional dst. This is the functional version of @render.\n\n\n\n\n\n","title":"HypertextTemplates.render"},{"category":"section","location":"getting-started/#Getting-Started","page":"Getting Started","text":"Welcome to HypertextTemplates.jl! This guide will help you get up and running with Julia's HTML templating system.","title":"Getting Started"},{"category":"section","location":"getting-started/#Installation","page":"Getting Started","text":"Add HypertextTemplates to your Julia project:\n\nusing Pkg\nPkg.add(\"HypertextTemplates\")\n\nOr in the Julia REPL's package mode (press ]):\n\npkg> add HypertextTemplates","title":"Installation"},{"category":"section","location":"getting-started/#First-Steps","page":"Getting Started","text":"","title":"First Steps"},{"category":"section","location":"getting-started/#Basic-Usage","page":"Getting Started","text":"Every HTML element is a Julia macro. Use @render to convert templates to HTML strings:\n\nusing HypertextTemplates\nusing HypertextTemplates.Elements\n\n# Render a simple HTML fragment\nhtml = @render @div begin\n    @h1 \"Welcome to HypertextTemplates!\"\n    @p \"This is a simple example.\"\nend\n\nMain.display_html(html) #hide","title":"Basic Usage"},{"category":"section","location":"getting-started/#Adding-Attributes","page":"Getting Started","text":"Attributes use {} syntax, similar to Julia NamedTuples:\n\nusing HypertextTemplates\nusing HypertextTemplates.Elements\n\nhtml = @render @div {id = \"main\", class = \"container\"} begin\n    @h1 {class = \"title\"} \"Styled Heading\"\n    @p {style = \"color: blue;\"} \"Blue text\"\nend\n\nMain.display_html(html) #hide","title":"Adding Attributes"},{"category":"section","location":"getting-started/#Using-Variables-and-Expressions","page":"Getting Started","text":"Use $ to interpolate variables and expressions. All values are automatically HTML-escaped for security:\n\nusing HypertextTemplates\nusing HypertextTemplates.Elements\n\nname = \"Julia\"\ncount = 42\n\nhtml = @render @div begin\n    @h1 \"Hello, \" $name \"!\"\n    @p \"The answer is \" $count\n    @p \"Double the answer: \" $(count * 2)\nend\n\nMain.display_html(html) #hide","title":"Using Variables and Expressions"},{"category":"section","location":"getting-started/#Building-a-Simple-Page","page":"Getting Started","text":"Let's create a complete HTML page structure:\n\nusing HypertextTemplates\nusing HypertextTemplates.Elements\n\n# Build a complete page\nhtml = @render @html begin\n    @head begin\n        @meta {charset = \"UTF-8\"}\n        @meta {name = \"viewport\", content = \"width=device-width, initial-scale=1.0\"}\n        @title \"My First Page\"\n    end\n    @body begin\n        @div {class = \"container\"} begin\n            @h1 \"My First Page\"\n            @section begin\n                @p \"Welcome to my website built with HypertextTemplates.jl!\"\n                @ul begin\n                    @li \"Fast rendering\"\n                    @li \"Type-safe templates\"\n                    @li \"Julia-native syntax\"\n                end\n            end\n        end\n    end\nend\n\nMain.display_html(html) #hide","title":"Building a Simple Page"},{"category":"section","location":"getting-started/#Working-with-Loops","page":"Getting Started","text":"Julia's control flow integrates naturally:\n\nusing HypertextTemplates\nusing HypertextTemplates.Elements\n\nitems = [\"Apple\", \"Banana\", \"Cherry\"]\n\nhtml = @render @ul begin\n    for item in items\n        @li $item\n    end\nend\n\nMain.display_html(html) #hide\n\nusing HypertextTemplates\nusing HypertextTemplates.Elements\n\nitems = [\"Apple\", \"Banana\", \"Cherry\"]\n\n# With enumeration\nhtml = @render @ol begin\n    for (i, item) in enumerate(items)\n        @li {value = i * 10} \"Item \" $i \": \" $item\n    end\nend\n\nMain.display_html(html) #hide","title":"Working with Loops"},{"category":"section","location":"getting-started/#Conditional-Rendering","page":"Getting Started","text":"Use standard Julia conditionals:\n\nusing HypertextTemplates\nusing HypertextTemplates.Elements\n\nuser_logged_in = true\nusername = \"julia_dev\"\n\nhtml = @render @div begin\n    if user_logged_in\n        @p \"Welcome back, \" $username \"!\"\n        @button \"Logout\"\n    else\n        @p \"Please log in to continue.\"\n        @button \"Login\"\n    end\nend\n\nMain.display_html(html) #hide","title":"Conditional Rendering"},{"category":"section","location":"getting-started/#Creating-Your-First-Component","page":"Getting Started","text":"Components are reusable template functions:\n\nusing HypertextTemplates\nusing HypertextTemplates.Elements\n\n@component function card(; title, description, link_url = nothing, link_text = \"Learn more\")\n    @div {class = \"card\"} begin\n        @h3 {class = \"card-title\"} $title\n        @p {class = \"card-description\"} $description\n        if !isnothing(link_url)\n            @a {href = link_url, class = \"card-link\"} $link_text\n        end\n    end\nend\n\n# Important: Create a macro shortcut for easier use\n@deftag macro card end\n\n# Now you can use @card instead of @<card\nhtml = @render @div {class = \"card-grid\"} begin\n    @card {\n        title = \"Getting Started\",\n        description = \"Learn the basics of HypertextTemplates.jl\"\n    }\n    @card {\n        title = \"Advanced Features\",\n        description = \"Explore components, slots, and more\",\n        link_url = \"/docs/advanced\",\n        link_text = \"Explore\"\n    }\nend\n\nMain.display_html(html) #hide","title":"Creating Your First Component"},{"category":"section","location":"getting-started/#Understanding-Components","page":"Getting Started","text":"Components are functions that accept props and generate HTML. Use @deftag to create a convenient macro shortcut:","title":"Understanding Components"},{"category":"section","location":"getting-started/#Components-with-Slots","page":"Getting Started","text":"Slots allow components to accept child content:\n\nusing HypertextTemplates\nusing HypertextTemplates.Elements\n\n@component function page(; title)\n    @html begin\n        @head begin\n            @meta {charset = \"UTF-8\"}\n            @meta {name = \"viewport\", content = \"width=device-width, initial-scale=1.0\"}\n            @title $title\n        end\n        @body begin\n            @div {class = \"container\"} begin\n                @h1 $title\n                @section begin\n                    @__slot__\n                end\n            end\n        end\n    end\nend\n\n@deftag macro page end\n\n# Use the page component with slot content\nhtml = @render @page {title = \"My First Page\"} begin\n    @p \"Welcome to my website built with HypertextTemplates.jl!\"\n    @ul begin\n        @li \"Fast rendering\"\n        @li \"Type-safe templates\"\n        @li \"Julia-native syntax\"\n    end\nend\n\nMain.display_html(html) #hide\n\nThe @__slot__ marker shows where child content renders inside the component.","title":"Components with Slots"},{"category":"section","location":"getting-started/#Rendering-to-Different-Outputs","page":"Getting Started","text":"By default, @render returns a String, but you can specify other outputs:\n\n# Render to an IO buffer\nio = IOBuffer()\n@render io @div \"Hello, IO!\"\nresult = String(take!(io))\n\n# Render to a byte array\nbytes = @render Vector{UInt8} @div \"Hello, bytes!\"\n\n# Render to a file\nopen(\"output.html\", \"w\") do file\n    @render file @html begin\n        @body @h1 \"Saved to file!\"\n    end\nend","title":"Rendering to Different Outputs"},{"category":"section","location":"getting-started/#Next-Steps","page":"Getting Started","text":"Now that you understand the basics:\n\nLearn about the Core Concepts underlying the DSL\nExplore the Component System for building reusable UI\nUnderstand HTML Elements & Attributes in detail\nDiscover Advanced Features for complex applications","title":"Next Steps"},{"category":"section","location":"getting-started/#Common-Pitfalls","page":"Getting Started","text":"Avoid these common mistakes when starting with HypertextTemplates:","title":"Common Pitfalls"},{"category":"section","location":"getting-started/#1.-Forgetting-for-Variables","page":"Getting Started","text":"# Wrong - variable not interpolated\nname = \"Julia\"\n@render @p \"Hello, name\"  # Output: <p>Hello, name</p>\n\n# Correct - use $ to interpolate\n@render @p \"Hello, \" $name  # Output: <p>Hello, Julia</p>","title":"1. Forgetting $ for Variables"},{"category":"section","location":"getting-started/#2.-Missing-begin...end-Blocks","page":"Getting Started","text":"# Wrong - syntax error\n@render @div\n    @h1 \"Title\"\n    @p \"Content\"\n\n# Correct - use begin...end for multiple elements\n@render @div begin\n    @h1 \"Title\"\n    @p \"Content\"\nend","title":"2. Missing begin...end Blocks"},{"category":"section","location":"getting-started/#3.-Wrong-Attribute-Syntax","page":"Getting Started","text":"# Wrong - using parentheses\n@render @div(class=\"container\") \"Content\"  # Syntax error!\n\n# Correct - use curly braces\n@render @div {class = \"container\"} \"Content\"","title":"3. Wrong Attribute Syntax"},{"category":"section","location":"getting-started/#4.-String-Literals-vs-Expressions","page":"Getting Started","text":"# String literals are NOT escaped (trusted content)\n@render @p \"<b>Bold</b>\"  # Output: <p><b>Bold</b></p>\n\n# Variables ARE escaped (safe from XSS)\ntext = \"<b>Bold</b>\"\n@render @p $text  # Output: <p>&lt;b&gt;Bold&lt;/b&gt;</p>","title":"4. String Literals vs Expressions"},{"category":"section","location":"getting-started/#5.-Component-Usage-Without-@deftag","page":"Getting Started","text":"# Define component\n@component function my_button(; text = \"Click\")\n    @button {class = \"btn\"} $text\nend\n\n# Wrong - can't use as macro without @deftag\n@render @my_button {text = \"Submit\"}  # Error!\n\n# Correct - either use @< or define a tag\n@render @<my_button {text = \"Submit\"}  # Works\n\n# Or better, define the tag\n@deftag macro my_button end\n@render @my_button {text = \"Submit\"}  # Now works!\n\nHappy templating with HypertextTemplates.jl!","title":"5. Component Usage Without @deftag"},{"category":"section","location":"elements-attributes/#HTML-Elements-and-Attributes","page":"Elements & Attributes","text":"This guide covers how to work with HTML elements and their attributes in HypertextTemplates.jl.","title":"HTML Elements & Attributes"},{"category":"section","location":"elements-attributes/#HTML-Element-Macros","page":"Elements & Attributes","text":"HypertextTemplates provides macros for all standard HTML elements. Import them from the Elements submodule:\n\nusing HypertextTemplates\nusing HypertextTemplates.Elements","title":"HTML Element Macros"},{"category":"section","location":"elements-attributes/#Common-Elements","page":"Elements & Attributes","text":"HypertextTemplates provides macros for every standard HTML element, allowing you to write HTML using Julia's native macro syntax. Each element is exposed as a macro (prefixed with @) that mirrors its HTML counterpart. These macros handle proper tag generation, nesting, attribute handling, and automatic escaping. The element macros are organized into logical groups based on their semantic purpose in HTML, making it easy to find and use the elements you need for structuring documents, creating forms, embedding media, or building complex layouts.\n\n# Structural elements\n@div @section @article @aside @header @footer @main @nav\n\n# Text content\n@h1 @h2 @h3 @h4 @h5 @h6 @p @span @blockquote @pre @code\n\n# Lists\n@ul @ol @li @dl @dt @dd\n\n# Links and media\n@a @img @video @audio @picture @source\n\n# Forms\n@form @input @button @select @option @textarea @label @fieldset\n\n# Tables\n@table @thead @tbody @tfoot @tr @th @td @caption @colgroup @col\n\n# And many more...","title":"Common Elements"},{"category":"section","location":"elements-attributes/#Complete-Example","page":"Elements & Attributes","text":"using HypertextTemplates\nusing HypertextTemplates.Elements\n\nhtml = @render @article begin\n    @header begin\n        @h1 \"Article Title\"\n        @p {class = \"meta\"} \"Published on \" Elements.@time {datetime = \"2024-01-01\"} \"January 1, 2024\"\n    end\n\n    @section begin\n        @p \"First paragraph of content...\"\n        @figure begin\n            @img {src = \"/image.jpg\", alt = \"Description\"}\n            @figcaption \"Image caption\"\n        end\n    end\n\n    @footer begin\n        @p \"Article footer with \" @a {href = \"/more\"} \"related links\"\n    end\nend\n\nMain.display_html(html) #hide","title":"Complete Example"},{"category":"section","location":"elements-attributes/#Attribute-Syntax","page":"Elements & Attributes","text":"","title":"Attribute Syntax"},{"category":"section","location":"elements-attributes/#Basic-Attributes","page":"Elements & Attributes","text":"Attributes are specified using {} with key-value pairs:\n\nusing HypertextTemplates\nusing HypertextTemplates.Elements\n\n# Single attribute\n@render @div {id = \"main\"} \"Content\"\nMain.display_html(ans) #hide\n\n# Multiple attributes\n@render @a {href = \"/home\", class = \"nav-link\", target = \"_blank\"} \"Home\"\nMain.display_html(ans) #hide\n\nusing HypertextTemplates\nusing HypertextTemplates.Elements\n\n# Computed attributes\nwidth = 300\nheight = 200\n@render @img {src = \"/photo.jpg\", width, height, alt = \"Photo\"}\n\nMain.display_html(ans) #hide","title":"Basic Attributes"},{"category":"section","location":"elements-attributes/#Attribute-Name-Variations","page":"Elements & Attributes","text":"","title":"Attribute Name Variations"},{"category":"section","location":"elements-attributes/#Standard-Identifiers","page":"Elements & Attributes","text":"For valid Julia identifiers, use simple syntax:\n\nusing HypertextTemplates\nusing HypertextTemplates.Elements\n\nhtml = @render @input {type = \"text\", name = \"username\", placeholder = \"Enter username\"}\n\nMain.display_html(html) #hide","title":"Standard Identifiers"},{"category":"section","location":"elements-attributes/#Non-Standard-Names","page":"Elements & Attributes","text":"For attributes with special characters, use string literals with :=:\n\nusing HypertextTemplates\nusing HypertextTemplates.Elements\n\n# Alpine.js attributes\nhtml = @render @div {\"x-data\" := \"{ open: false }\"} begin\n    @button {\"@click\" := \"open = !open\"} \"Toggle\"\n    @div {\"x-show\" := \"open\"} \"Hidden content\"\nend\n\nMain.display_html(html) #hide\n\nusing HypertextTemplates\nusing HypertextTemplates.Elements\n\n# HTMX attributes\nhtml = @render @button {\n    \"hx-post\" := \"/api/click\",\n    \"hx-target\" := \"#result\",\n    \"hx-swap\" := \"innerHTML\"\n} \"Click me\"\n\nMain.display_html(html) #hide\n\nusing HypertextTemplates\nusing HypertextTemplates.Elements\n\n# Custom data attributes\nhtml = @render @div {\n    \"data-user-id\" := \"123\",\n    \"data-role\" := \"admin\",\n    \"aria-label\" := \"User profile\"\n} \"Content\"\n\nMain.display_html(html) #hide","title":"Non-Standard Names"},{"category":"section","location":"elements-attributes/#Attribute-Value-Types","page":"Elements & Attributes","text":"","title":"Attribute Value Types"},{"category":"section","location":"elements-attributes/#Strings","page":"Elements & Attributes","text":"@div {class = \"container\", id = \"main\"}","title":"Strings"},{"category":"section","location":"elements-attributes/#Numbers","page":"Elements & Attributes","text":"Numbers are automatically converted to strings:\n\nusing HypertextTemplates\nusing HypertextTemplates.Elements\n\n@render @input {type = \"range\", min = 0, max = 100, step = 5}\n\nMain.display_html(ans) #hide","title":"Numbers"},{"category":"section","location":"elements-attributes/#Booleans","page":"Elements & Attributes","text":"Boolean attributes follow HTML5 semantics:\n\nusing HypertextTemplates\nusing HypertextTemplates.Elements\n\n# true renders just the attribute name\n@render @input {type = \"checkbox\", checked = true}\n\nMain.display_html(ans) #hide\n\n# false omits the attribute entirely  \n@render @input {type = \"checkbox\", checked = false}\n\nMain.display_html(ans) #hide\n\n# Dynamic boolean\nis_loading = true\n@render @button {disabled = is_loading} \"Submit\"\n\nMain.display_html(ans) #hide","title":"Booleans"},{"category":"section","location":"elements-attributes/#Nothing/Missing","page":"Elements & Attributes","text":"nothing values are omitted:\n\nusing HypertextTemplates\nusing HypertextTemplates.Elements\n\n# Test with false condition\ncondition = false\noptional_class = condition ? \"active\" : nothing\nhtml1 = @render @div {class = optional_class} \"Content\"\n\nMain.display_html(html1) #hide\n\n# Test with true condition\ncondition = true\noptional_class = condition ? \"active\" : nothing\nhtml2 = @render @div {class = optional_class} \"Content\"\n\nMain.display_html(html2) #hide","title":"Nothing/Missing"},{"category":"section","location":"elements-attributes/#Attribute-Shortcuts","page":"Elements & Attributes","text":"","title":"Attribute Shortcuts"},{"category":"section","location":"elements-attributes/#Variable-Name-Matching","page":"Elements & Attributes","text":"When variable names match attribute names:\n\nusing HypertextTemplates\nusing HypertextTemplates.Elements\n\nid = \"user-123\"\nclass = \"profile-card\"\nrole = \"article\"\n\n# Instead of {id = id, class = class, role = role}\n@render @div {id, class, role} \"Content\"\n\nMain.display_html(ans) #hide","title":"Variable Name Matching"},{"category":"section","location":"elements-attributes/#Spreading-Attributes","page":"Elements & Attributes","text":"Use ... to spread attributes from collections:\n\nusing HypertextTemplates\nusing HypertextTemplates.Elements\n\n# From NamedTuple\ncommon_attrs = (class = \"btn\", type = \"button\")\n@render @button {id = \"submit\", common_attrs...} \"Submit\"\n\nMain.display_html(ans) #hide\n\nusing HypertextTemplates\nusing HypertextTemplates.Elements\n\n# From Dict\nattrs = Dict(Symbol(\"data-value\") => \"123\", Symbol(\"data-label\") => \"test\")\n@render @div {class = \"widget\", attrs...} \"Content\"\n\nMain.display_html(ans) #hide\n\nusing HypertextTemplates\nusing HypertextTemplates.Elements\n\n# Combining multiple sources\nbase = (; class = \"card\")\nextra = (; id = \"main\", role = \"region\")\n@render @article {base..., extra..., class = \"card featured\"} \"Content\"\n# Note: Later values override earlier ones\n\nMain.display_html(ans) #hide","title":"Spreading Attributes"},{"category":"section","location":"elements-attributes/#Conditional-Attributes","page":"Elements & Attributes","text":"Common patterns for conditional attributes:\n\nusing HypertextTemplates\nusing HypertextTemplates.Elements\n\n# Using ternary operator\nisactive = true\nhtml = @render @div {class = isactive ? \"active\" : \"inactive\"} \"Status\"\n\nMain.display_html(html) #hide\n\nusing HypertextTemplates\nusing HypertextTemplates.Elements\n\n# Using nothing for optional attributes\nexternal = true\nhtml = @render @a {\n    href = \"/page\",\n    target = external ? \"_blank\" : nothing,\n    rel = external ? \"noopener\" : nothing\n} \"External Link\"\n\nMain.display_html(html) #hide\n\nusing HypertextTemplates\nusing HypertextTemplates.Elements\n\n# Building class lists\nsize = :large\nvariant = :primary\ndisabled = true\n\nclasses = [\n    \"btn\",\n    size == :large ? \"btn-lg\" : \"btn-sm\",\n    variant == :primary ? \"btn-primary\" : \"btn-secondary\",\n    disabled ? \"disabled\" : nothing\n] |> x -> filter(!isnothing, x) |> x -> join(x, \" \")\n\nhtml = @render @button {class = classes, disabled} \"Click\"\n\nMain.display_html(html) #hide","title":"Conditional Attributes"},{"category":"section","location":"elements-attributes/#Custom-Elements","page":"Elements & Attributes","text":"","title":"Custom Elements"},{"category":"section","location":"elements-attributes/#Defining-Custom-Elements","page":"Elements & Attributes","text":"Use @element to define custom HTML elements:\n\nusing HypertextTemplates\nusing HypertextTemplates.Elements\n\n# Define a web component\n@element \"my-component\" my_component\n\n# Use it\nhtml = @render @<my_component {prop = \"value\"} \"Content\"\n\nMain.display_html(html) #hide","title":"Defining Custom Elements"},{"category":"section","location":"elements-attributes/#Creating-Element-Macros","page":"Elements & Attributes","text":"Use @deftag to create macro shortcuts:\n\nusing HypertextTemplates\nusing HypertextTemplates.Elements\n\n# Define the element\n@element \"custom-button\" custom_button\n\n# Create a macro for it\n@deftag macro custom_button end\n\n# Now use as a regular macro\nhtml = @render @custom_button {variant = \"primary\"} \"Click me\"\n\nMain.display_html(html) #hide","title":"Creating Element Macros"},{"category":"section","location":"elements-attributes/#Web-Components-Example","page":"Elements & Attributes","text":"using HypertextTemplates\nusing HypertextTemplates.Elements\n\n# Define common web components\n@element \"sl-button\" sl_button\n@element \"sl-input\" sl_input\n@element \"sl-card\" sl_card\n\n@deftag macro sl_button end\n@deftag macro sl_input end  \n@deftag macro sl_card end\n\n# Use Shoelace components\nhtml = @render @sl_card begin\n    @div {slot = \"header\"} \"Card Title\"\n    @p \"Card content\"\n    @div {slot = \"footer\"} begin\n        @sl_button {variant = \"primary\"} \"Save\"\n    end\nend\n\nMain.display_html(html) #hide","title":"Web Components Example"},{"category":"section","location":"elements-attributes/#Special-Elements","page":"Elements & Attributes","text":"","title":"Special Elements"},{"category":"section","location":"elements-attributes/#Void-Elements","page":"Elements & Attributes","text":"Self-closing elements work automatically:\n\nusing HypertextTemplates\nusing HypertextTemplates.Elements\n\nhtml = @render @div begin\n    @img {src = \"/photo.jpg\", alt = \"\"}\n    @br\n    @hr {class = \"divider\"}\n    @input {type = \"text\", name = \"field\"}\n    @meta {charset = \"UTF-8\"}\nend\n\nMain.display_html(html) #hide","title":"Void Elements"},{"category":"section","location":"elements-attributes/#Raw-HTML-with-Script-and-Style","page":"Elements & Attributes","text":"Script and style elements preserve their content:\n\nusing HypertextTemplates\nusing HypertextTemplates.Elements\n\nhtml = @render @div begin\n    @script {type = \"text/javascript\"} \"\"\"\n        console.log(\"This is preserved as-is\");\n        const data = { value: 123 };\n    \"\"\"\n\n    @style \"\"\"\n        .custom-class {\n            color: blue;\n            font-size: 16px;\n        }\n    \"\"\"\nend\n\nMain.display_html(html) #hide","title":"Raw HTML with Script and Style"},{"category":"section","location":"elements-attributes/#SVG-Elements","page":"Elements & Attributes","text":"SVG elements work like regular elements:\n\nusing HypertextTemplates\nusing HypertextTemplates.Elements\n\n@element \"svg\" svg\n@element \"circle\" circle\n@element \"rect\" rect\n@element \"path\" path\n\n@deftag macro svg end\n@deftag macro circle end\n@deftag macro rect end\n@deftag macro path end\n\nhtml = @render @svg {width = \"100\", height = \"100\", viewBox = \"0 0 100 100\"} begin\n    @circle {cx = \"50\", cy = \"50\", r = \"40\", fill = \"blue\"}\n    @rect {x = \"10\", y = \"10\", width = \"30\", height = \"30\", fill = \"red\"}\n    @path {d = \"M 10 10 L 90 90\", stroke = \"black\", \"stroke-width\" := \"2\"}\nend\n\nMain.display_html(html) #hide","title":"SVG Elements"},{"category":"section","location":"elements-attributes/#Escaping-and-Security","page":"Elements & Attributes","text":"","title":"Escaping and Security"},{"category":"section","location":"elements-attributes/#Automatic-Escaping","page":"Elements & Attributes","text":"Attribute values from variables are automatically escaped:\n\nusing HypertextTemplates\nusing HypertextTemplates.Elements\n\nuser_input = \"\\\" onclick=\\\"alert('xss')\\\"\"\nhtml = @render @div {title = user_input} \"Safe\"\n# Output shows escaped attributes\n\nMain.display_html(html) #hide","title":"Automatic Escaping"},{"category":"section","location":"elements-attributes/#Pre-escaped-Content","page":"Elements & Attributes","text":"In rare cases where you need to include pre-escaped or specially formatted attribute values that should bypass the automatic escaping system, you can use SafeString. This is typically needed when working with attribute values that have already been processed by another system or contain special formatting that must be preserved exactly. However, this should be used with extreme caution and only with trusted content, as it bypasses the security protections that prevent XSS attacks through attribute injection.\n\nusing HypertextTemplates\nusing HypertextTemplates.Elements\n\nsafe_attr = SafeString(\"complex&value\")\nhtml = @render @div {\"data-value\" := safe_attr} \"Content\"\n\nMain.display_html(html) #hide","title":"Pre-escaped Content"},{"category":"section","location":"elements-attributes/#Advanced-Patterns","page":"Elements & Attributes","text":"","title":"Advanced Patterns"},{"category":"section","location":"elements-attributes/#Dynamic-Attribute-Names","page":"Elements & Attributes","text":"Build attributes programmatically:\n\nusing HypertextTemplates\nusing HypertextTemplates.Elements\n\n@component function dynamic_attrs(; prefix = \"data\", values = Dict())\n    attrs = Dict()\n    for (key, value) in values\n        attrs[Symbol(\"$prefix-$key\")] = value\n    end\n\n    @div {attrs...} @__slot__\nend\n\n@deftag macro dynamic_attrs end\n\n# Usage example\nhtml = @render @dynamic_attrs {\n    prefix = \"data\",\n    values = Dict(\"id\" => \"123\", \"name\" => \"test\")\n} \"Content with dynamic attributes\"\n\nMain.display_html(html) #hide","title":"Dynamic Attribute Names"},{"category":"section","location":"elements-attributes/#ARIA-Attributes","page":"Elements & Attributes","text":"Accessibility attributes using proper patterns:\n\nusing HypertextTemplates\nusing HypertextTemplates.Elements\n\n@component function accessible_modal(; open = false, title_id = \"modal-title\")\n    @div {\n        role = \"dialog\",\n        \"aria-modal\" := \"true\",\n        \"aria-labelledby\" := title_id,\n        \"aria-hidden\" := !open\n    } begin\n        @h2 {id = title_id} begin\n            @__slot__ title\n        end\n        @div begin\n            @__slot__\n        end\n    end\nend\n\n@deftag macro accessible_modal end\n\n# Usage example\nhtml = @render @accessible_modal {open = true} begin\n    title := \"Important Dialog\"\n    @p \"This is the modal content.\"\nend\n\nMain.display_html(html) #hide","title":"ARIA Attributes"},{"category":"section","location":"elements-attributes/#Style-Objects","page":"Elements & Attributes","text":"Building inline styles:\n\nusing HypertextTemplates\nusing HypertextTemplates.Elements\n\nfunction style_string(; styles...)\n    parts = String[]\n    for (prop, value) in pairs(styles)\n        prop_str = replace(string(prop), \"_\" => \"-\")\n        push!(parts, \"$prop_str: $value\")\n    end\n    return join(parts, \"; \")\nend\n\n# Usage\nhtml = @render @div {\n    style = style_string(\n        background_color = \"blue\",\n        padding = \"1rem\",\n        border_radius = \"0.5rem\"\n    )\n} \"Styled div\"\n\nMain.display_html(html) #hide","title":"Style Objects"},{"category":"section","location":"elements-attributes/#Best-Practices","page":"Elements & Attributes","text":"","title":"Best Practices"},{"category":"section","location":"elements-attributes/#1.-Use-Semantic-HTML","page":"Elements & Attributes","text":"Choose elements that convey meaning:\n\nusing HypertextTemplates\nusing HypertextTemplates.Elements\n\n# Good: Semantic elements\nhtml = @render @nav begin\n    @ul begin\n        @li @a {href = \"/\"} \"Home\"\n        @li @a {href = \"/about\"} \"About\"\n    end\nend\n\nMain.display_html(html) #hide\n\n# Article with semantic structure\nhtml2 = @render @article begin\n    @header @h1 \"Article Title\"\n    @section @p \"Content...\"\n    @footer @button {type = \"submit\"} \"Submit\"\nend\n\nMain.display_html(html2) #hide","title":"1. Use Semantic HTML"},{"category":"section","location":"elements-attributes/#2.-Accessibility-First","page":"Elements & Attributes","text":"Always include accessibility attributes:\n\nusing HypertextTemplates\nusing HypertextTemplates.Elements\n\nhtml = @render @div begin\n    @img {src = \"/logo.png\", alt = \"Company logo\"}\n    @button {type = \"button\", \"aria-label\" := \"Close dialog\"} \"×\"\n    @input {type = \"email\", id = \"email\", \"aria-describedby\" := \"email-error\"}\n    @span {id = \"email-error\", class = \"error\"} \"Please enter a valid email\"\nend\n\nMain.display_html(html) #hide","title":"2. Accessibility First"},{"category":"section","location":"elements-attributes/#3.-Consistent-Naming","page":"Elements & Attributes","text":"Use consistent patterns for classes and IDs:\n\n# Component-based naming\n@div {class = \"card\"} begin\n    @div {class = \"card__header\"} \"Title\"\n    @div {class = \"card__body\"} \"Content\"\n    @button {class = \"card__action card__action--primary\"} \"Save\"\nend","title":"3. Consistent Naming"},{"category":"section","location":"elements-attributes/#4.-Avoid-Inline-Styles","page":"Elements & Attributes","text":"Prefer classes over inline styles:\n\n# Good: Use classes\n@div {class = \"alert alert-warning\"} \"Warning message\"\n\n# Avoid: Inline styles (except when dynamic)\n@div {style = \"color: orange; padding: 1rem;\"} \"Warning\"","title":"4. Avoid Inline Styles"},{"category":"section","location":"elements-attributes/#5.-Data-Attributes-for-JavaScript","page":"Elements & Attributes","text":"Use data attributes for JavaScript hooks:\n\nusing HypertextTemplates\nusing HypertextTemplates.Elements\n\nhtml = @render @button {\n    class = \"btn btn-primary\",\n    \"data-action\" := \"submit-form\",\n    \"data-form-id\" := \"user-form\",\n    \"data-confirm\" := \"true\"\n} \"Submit\"\n\nMain.display_html(html) #hide","title":"5. Data Attributes for JavaScript"},{"category":"section","location":"elements-attributes/#Summary","page":"Elements & Attributes","text":"HypertextTemplates.jl provides a comprehensive and flexible system for working with HTML elements and attributes:\n\nAll standard HTML elements available as macros\nFlexible attribute syntax with {} notation\nSupport for dynamic and computed attributes\nAutomatic security through escaping\nCustom element definition support\nAdvanced patterns for complex use cases\n\nThe system is designed to feel natural to Julia developers while providing all the features needed for modern web development.","title":"Summary"},{"category":"section","location":"rendering/#Rendering-and-Performance","page":"Rendering & Performance","text":"This guide covers the rendering system in HypertextTemplates.jl, including performance optimization techniques and advanced rendering patterns.","title":"Rendering & Performance"},{"category":"section","location":"rendering/#The-@render-Macro","page":"Rendering & Performance","text":"The @render macro is the primary way to convert templates into output. It supports multiple output targets and streaming capabilities.","title":"The @render Macro"},{"category":"section","location":"rendering/#Basic-Rendering","page":"Rendering & Performance","text":"The @render macro converts your template expressions into HTML output. By default, it returns a String containing the rendered HTML. You can render single elements or multiple elements in a block, and the macro handles all the necessary HTML generation including proper escaping and tag structure.\n\nusing HypertextTemplates\nusing HypertextTemplates.Elements\n\n# Render to String (default)\nhtml = @render @div \"Hello, World!\"\n\nMain.display_html(html) #hide\n\n# Render multiple elements\nhtml2 = @render begin\n    @h1 \"Title\"\n    @p \"Paragraph\"\nend\n\nMain.display_html(html2) #hide","title":"Basic Rendering"},{"category":"section","location":"rendering/#Rendering-to-IO","page":"Rendering & Performance","text":"When building web applications or generating large documents, rendering directly to an IO stream avoids the memory overhead of creating intermediate strings. This approach is particularly beneficial for server responses where you can write directly to the network socket, or when generating files where you can stream directly to disk. The syntax is identical to string rendering - just pass an IO object as the first argument.\n\nusing HypertextTemplates\nusing HypertextTemplates.Elements\n\n# Render to IOBuffer\nbuffer = IOBuffer()\n@render buffer @div begin\n    @h1 \"Small Document\"\n    for i in 1:3\n        @p \"Paragraph $i\"\n    end\nend\nresult = String(take!(buffer))\n\nMain.display_html(result) #hide","title":"Rendering to IO"},{"category":"section","location":"rendering/#Output-Type-Control","page":"Rendering & Performance","text":"Specify the desired output type:\n\nusing HypertextTemplates\nusing HypertextTemplates.Elements\n\n# Render to String (explicit)\nstr = @render String @div \"Content\"\nprintln(typeof(str), \": \", str)\n\n# Render to Vector{UInt8}\nbytes = @render Vector{UInt8} @div \"Binary content\"\nprintln(typeof(bytes), \": \", String(bytes))","title":"Output Type Control"},{"category":"section","location":"rendering/#Zero-Allocation-Design","page":"Rendering & Performance","text":"HypertextTemplates is designed to minimize memory allocations during rendering.","title":"Zero-Allocation Design"},{"category":"section","location":"rendering/#Direct-IO-Streaming","page":"Rendering & Performance","text":"Instead of building intermediate representations, content streams directly:\n\nusing HypertextTemplates\nusing HypertextTemplates.Elements\n\n# This creates no intermediate strings or DOM objects\ntitle = \"My Article\"\nparagraphs = [\"First paragraph.\", \"Second paragraph.\", \"Third paragraph.\"]\n\nio = IOBuffer()\n@render io @article begin\n    @h1 $title\n    for paragraph in paragraphs\n        @p $paragraph\n    end\nend\n\nresult = String(take!(io))\nMain.display_html(result) #hide\n\n# This is equivalent to manual IO operations:\n# write(io, \"<article>\")\n# write(io, \"<h1>\")\n# write(io, escaped_title)\n# write(io, \"</h1>\")\n# ...","title":"Direct IO Streaming"},{"category":"section","location":"rendering/#Precompiled-Templates","page":"Rendering & Performance","text":"HypertextTemplates performs compile-time optimization on your templates by identifying static HTML content and precompiling it. This means that any HTML structure that doesn't contain dynamic values (interpolations with $) is transformed into efficient string literals at compile time. When you render the template, only the dynamic parts need processing, while static HTML is emitted directly. This optimization happens automatically and can dramatically improve performance for templates with mostly static content.\n\nusing HypertextTemplates\nusing HypertextTemplates.Elements\n\n@component function static_heavy()\n    # All static HTML is precompiled\n    @div {class = \"container\"} begin\n        @header {class = \"header\"} begin\n            @nav begin\n                @a {href = \"/\"} \"Home\"\n                @a {href = \"/about\"} \"About\"\n            end\n        end\n        @article {class = \"content\"} begin\n            @__slot__  # Only dynamic part\n        end\n    end\nend\n\n@deftag macro static_heavy end\n\n# When rendered, only the slot content is processed at runtime\nhtml = @render @static_heavy begin\n    @p \"This is the dynamic content that goes in the slot.\"\nend\n\nMain.display_html(html) #hide","title":"Precompiled Templates"},{"category":"section","location":"rendering/#Efficient-String-Handling","page":"Rendering & Performance","text":"The rendering system uses efficient string operations:\n\nusing HypertextTemplates\nusing HypertextTemplates.Elements\n\n# Strings are written directly, not concatenated\n@component function efficient_list(; items)\n    @ul begin\n        for item in items\n            # Each write is a separate IO operation\n            # No string concatenation happens\n            @li $item\n        end\n    end\nend\n\n@deftag macro efficient_list end\n\nitems = [\"Apple\", \"Banana\", \"Cherry\", \"Date\", \"Elderberry\"]\nhtml = @render @efficient_list {items}\nMain.display_html(html) #hide","title":"Efficient String Handling"},{"category":"section","location":"rendering/#StreamingRender","page":"Rendering & Performance","text":"For large documents or slow-loading content, use StreamingRender to send content as it becomes available.","title":"StreamingRender"},{"category":"section","location":"rendering/#Basic-Streaming","page":"Rendering & Performance","text":"using HypertextTemplates\nusing HypertextTemplates.Elements\n\n# Create a streaming render iterator\nstream = StreamingRender() do io\n    @render io @div begin\n        @h1 \"Streaming Example\"\n\n        # Render multiple sections\n        for i in 1:3\n            @section begin\n                @h2 \"Section $i\"\n                @p \"This is paragraph $i\"\n            end\n        end\n    end\nend\n\n# Consume the stream\nchunks = String[]\nfor chunk in stream\n    push!(chunks, String(chunk))\nend\n\nprintln(\"Streamed $(length(chunks)) chunks:\")\nfor (i, chunk) in enumerate(chunks)\n    println(\"Chunk $i: \", repr(chunk))\nend","title":"Basic Streaming"},{"category":"section","location":"rendering/#HTTP-Streaming-Example","page":"Rendering & Performance","text":"With HTTP.jl:\n\nusing HypertextTemplates\nusing HypertextTemplates.Elements\n\n# Simulated streaming example (without actual HTTP.jl dependency)\nfunction simulate_streaming_response()\n    chunks = String[]\n\n    for chunk in StreamingRender() do render_io\n        @render render_io @html begin\n            @head @title \"Streaming Page\"\n            @body begin\n                @h1 \"Live Data\"\n                for i in 1:5  # Reduced for example\n                    @p \"Item $i\"\n                end\n            end\n        end\n    end\n        push!(chunks, String(chunk))\n    end\n\n    return chunks\nend\n\n# Show how the content would be streamed\nchunks = simulate_streaming_response()\nprintln(\"Streamed $(length(chunks)) chunks\")\nfor (i, chunk) in enumerate(chunks[1:min(3, length(chunks))])\n    println(\"\\nChunk $i preview: \", first(chunk, 100), \"...\")\nend","title":"HTTP Streaming Example"},{"category":"section","location":"rendering/#Micro-batching","page":"Rendering & Performance","text":"StreamingRender uses intelligent micro-batching for optimal performance:\n\nusing HypertextTemplates\nusing HypertextTemplates.Elements\n\n# Internal behavior:\n# - Large writes (≥64 bytes): Sent immediately\n# - Small writes: Batched up to 256 bytes or 1ms timeout\n# - Configurable via keyword arguments to `StreamingRender`\n\n# This results in efficient chunking\nchunks = String[]\nfor chunk in StreamingRender() do io\n    @render io @ul begin\n        for i in 1:20  # Reduced for example\n            @li \"Item $i\"  # Small writes are batched\n        end\n    end\nend\n    push!(chunks, String(chunk))\nend\n\nprintln(\"Total chunks: \", length(chunks))\nif !isempty(chunks)\n    println(\"First chunk size: \", length(chunks[1]), \" bytes\")\n    println(\"First chunk preview: \", first(chunks[1], 100), \"...\")\nend","title":"Micro-batching"},{"category":"section","location":"rendering/#StreamingRender-Configuration","page":"Rendering & Performance","text":"Configure streaming behavior:\n\nusing HypertextTemplates\nusing HypertextTemplates.Elements\n\n# Example showing configuration (without actual large document)\n@component function sample_document()\n    @div begin\n        @h1 \"Document Title\"\n        for i in 1:10\n            @section begin\n                @h2 \"Section $i\"\n                @p \"Content for section $i\"\n            end\n        end\n    end\nend\n\n@deftag macro sample_document end\n\n# Custom buffering settings\nio_buffer = IOBuffer()\nio = IOContext(\n    io_buffer,\n)\n\nchunks = String[]\nfor chunk in StreamingRender(;\n    buffer_size = 512,\n    immediate_threshold = 128,\n) do render_io\n    @render IOContext(render_io, io) @sample_document\nend\n    push!(chunks, String(chunk))\nend\n\nprintln(\"Configured streaming produced \", length(chunks), \" chunks\")","title":"StreamingRender Configuration"},{"category":"section","location":"rendering/#Advanced-Patterns","page":"Rendering & Performance","text":"","title":"Advanced Patterns"},{"category":"section","location":"rendering/#Buffered-Rendering","page":"Rendering & Performance","text":"For complex layouts, use intermediate buffers:\n\nusing HypertextTemplates\nusing HypertextTemplates.Elements\n\n@component function left_content()\n    @nav begin\n        @h3 \"Navigation\"\n        @ul begin\n            @li @a {href = \"/\"} \"Home\"\n            @li @a {href = \"/about\"} \"About\"\n            @li @a {href = \"/contact\"} \"Contact\"\n        end\n    end\nend\n\n@component function right_content()\n    @article begin\n        @h2 \"Main Content\"\n        @p \"This is the main content area.\"\n        @p \"It contains the primary information.\"\n    end\nend\n\n@component function two_column_layout(; left_content, right_content)\n    # Render columns in parallel (conceptually)\n    left_buffer = IOBuffer()\n    right_buffer = IOBuffer()\n\n    @render left_buffer @div {class = \"column-left\"} left_content()\n    @render right_buffer @div {class = \"column-right\"} right_content()\n\n    # Combine results\n    @div {class = \"two-column\"} begin\n        @text SafeString(String(take!(left_buffer)))\n        @text SafeString(String(take!(right_buffer)))\n    end\nend\n\n@deftag macro two_column_layout end\n\n# Example usage\nhtml = @render @two_column_layout {left_content, right_content}\n\nMain.display_html(html) #hide","title":"Buffered Rendering"},{"category":"section","location":"rendering/#Lazy-Rendering","page":"Rendering & Performance","text":"Defer expensive computations:\n\nusing HypertextTemplates\nusing HypertextTemplates.Elements\n\n@component function render_data(; data)\n    @div begin\n        @h3 $(data.title)\n        @ul begin\n            for item in data.items\n                @li $item\n            end\n        end\n    end\nend\n\n@component function lazy_section(; data_loader)\n    @div {class = \"lazy-load\"} begin\n        # Only load data when actually rendering\n        data = data_loader()\n\n        if isnothing(data)\n            @p \"No data available\"\n        else\n            render_data(; data)\n        end\n    end\nend\n\n@deftag macro lazy_section end\n\n# Simulate expensive operations\nfunction expensive_database_query()\n    # In real code, this would be a database call\n    return (title = \"Query Results\", items = [\"Result 1\", \"Result 2\", \"Result 3\"])\nend\n\nfunction empty_query()\n    return nothing\nend\n\n# Example with data\nhtml1 = @render @lazy_section {\n    data_loader = () -> expensive_database_query()\n}\nMain.display_html(html1) #hide\n\n# Example without data\nhtml2 = @render @lazy_section {\n    data_loader = () -> empty_query()\n}\nMain.display_html(html2) #hide","title":"Lazy Rendering"},{"category":"section","location":"rendering/#Progressive-Enhancement","page":"Rendering & Performance","text":"Render basic content first, enhance later:\n\nusing HypertextTemplates\nusing HypertextTemplates.Elements\n\n@component function progressive_gallery(; images)\n    @div {class = \"gallery\"} begin\n        # Basic version (fast)\n        for (i, img) in enumerate(images)\n            @img {\n                src = img.thumbnail,\n                \"data-full-src\" := img.full_size,\n                loading = \"lazy\",\n                alt = img.alt\n            }\n        end\n\n        # Enhancement script\n        @script \"\"\"\n        // Progressively load full images\n        document.querySelectorAll('[data-full-src]').forEach(img => {\n            // Load full size when visible\n        });\n        \"\"\"\n    end\nend\n\n@deftag macro progressive_gallery end\n\n# Example usage\nimages = [\n    (thumbnail = \"/thumb1.jpg\", full_size = \"/full1.jpg\", alt = \"Image 1\"),\n    (thumbnail = \"/thumb2.jpg\", full_size = \"/full2.jpg\", alt = \"Image 2\"),\n    (thumbnail = \"/thumb3.jpg\", full_size = \"/full3.jpg\", alt = \"Image 3\")\n]\n\nhtml = @render @progressive_gallery {images}\nMain.display_html(html) #hide","title":"Progressive Enhancement"},{"category":"section","location":"rendering/#Best-Practices","page":"Rendering & Performance","text":"","title":"Best Practices"},{"category":"section","location":"rendering/#1.-Choose-the-Right-Output","page":"Rendering & Performance","text":"Use IO for server responses\nUse String for testing or caching\nUse StreamingRender for large/slow content","title":"1. Choose the Right Output"},{"category":"section","location":"rendering/#2.-Minimize-Dynamic-Content","page":"Rendering & Performance","text":"using HypertextTemplates\nusing HypertextTemplates.Elements\n\n# Good: Static structure, dynamic content\n@component function good_list(; items)\n    @ul {class = \"static-class\"} begin\n        for item in items\n            @li $item  # Only content is dynamic\n        end\n    end\nend\n\n@deftag macro good_list end\n\n# Less optimal: Dynamic structure\nfunction compute_class(items)\n    length(items) > 5 ? \"long-list\" : \"short-list\"\nend\n\nfunction compute_item_class(item)\n    startswith(item, \"A\") ? \"a-item\" : \"other-item\"\nend\n\n@component function suboptimal_list(; items)\n    @ul {class = compute_class(items)} begin  # Computed every render\n        for item in items\n            @li {class = compute_item_class(item)} $item\n        end\n    end\nend\n\n@deftag macro suboptimal_list end\n\n# Example usage\nitems = [\"Apple\", \"Banana\", \"Cherry\"]\n\n@render @good_list {items}\n\nMain.display_html(ans) #hide\n\n@render @suboptimal_list {items}\n\nMain.display_html(ans) #hide","title":"2. Minimize Dynamic Content"},{"category":"section","location":"rendering/#Summary","page":"Rendering & Performance","text":"HypertextTemplates.jl's rendering system provides:\n\nZero-allocation design for maximum performance\nFlexible output targets (String, IO, custom types)\nStreaming support for large/async content  \nMicro-batching for optimal chunking\nDirect IO operations avoiding intermediate strings\n\nThe key to performance is understanding that templates compile to direct IO operations, making HypertextTemplates as fast as hand-written HTML generation code while maintaining the convenience of a DSL.","title":"Summary"},{"category":"section","location":"core-concepts/#Core-Concepts","page":"Core Concepts","text":"Understanding the core concepts of HypertextTemplates.jl will help you use the library effectively and write maintainable templates.","title":"Core Concepts"},{"category":"section","location":"core-concepts/#Macro-Based-DSL-Philosophy","page":"Core Concepts","text":"HypertextTemplates.jl uses Julia's macro system to create a domain-specific language (DSL) for HTML generation. This approach provides several benefits:","title":"Macro-Based DSL Philosophy"},{"category":"section","location":"core-concepts/#Compile-Time-Optimization","page":"Core Concepts","text":"using HypertextTemplates\nusing HypertextTemplates.Elements\n\n# This macro call...\nhtml = @render @div {class = \"container\"} @p \"Hello\"\n\nMain.display_html(html) #hide","title":"Compile-Time Optimization"},{"category":"section","location":"core-concepts/#Native-Julia-Integration","page":"Core Concepts","text":"The DSL feels like natural Julia code because it is Julia code:\n\nusing HypertextTemplates\nusing HypertextTemplates.Elements\n\n# Regular Julia control flow works seamlessly\n@render @ul begin\n    for i in 1:5\n        if isodd(i)\n            @li {class = \"odd\"} \"Item \" $i\n        else\n            @li {class = \"even\"} \"Item \" $i\n        end\n    end\nend\n\nMain.display_html(ans) #hide","title":"Native Julia Integration"},{"category":"section","location":"core-concepts/#Type-Safety","page":"Core Concepts","text":"Julia's type system helps catch errors at compile time:\n\nusing HypertextTemplates\nusing HypertextTemplates.Elements\n\n@component function typed_list(; items::Vector{String})\n    @ul begin\n        for item in items\n            @li $item\n        end\n    end\nend\n\n@deftag macro typed_list end\n\n# Julia's type system helps catch errors\nitems = [\"Apple\", \"Banana\", \"Cherry\"]\nhtml = @render @typed_list {items}\n\nMain.display_html(html) #hide","title":"Type Safety"},{"category":"section","location":"core-concepts/#The-{}-Attribute-Syntax","page":"Core Concepts","text":"Building on the macro foundation, attributes use a special {} syntax that resembles Julia's NamedTuple syntax:","title":"The {} Attribute Syntax"},{"category":"section","location":"core-concepts/#Basic-Attributes","page":"Core Concepts","text":"using HypertextTemplates\nusing HypertextTemplates.Elements\n\n# Simple attributes\n@render @div {id = \"main\", class = \"container\"} \"Content\"\n\nMain.display_html(ans) #hide\n\nusing HypertextTemplates\nusing HypertextTemplates.Elements\n\n# Computed attributes\nwidth = 100\n@render @img {src = \"/logo.png\", width = width * 2}\n\nMain.display_html(ans) #hide","title":"Basic Attributes"},{"category":"section","location":"core-concepts/#Attribute-Name-Shortcuts","page":"Core Concepts","text":"When variable names match attribute names:\n\nusing HypertextTemplates\nusing HypertextTemplates.Elements\n\nclass = \"active\"\ndisabled = true\n\n# Instead of {class = class, disabled = disabled}\n@render @button {class, disabled} \"Click me\"\n\nMain.display_html(ans) #hide","title":"Attribute Name Shortcuts"},{"category":"section","location":"core-concepts/#Attribute-Spreading","page":"Core Concepts","text":"Spread multiple attributes from a collection:\n\nusing HypertextTemplates\nusing HypertextTemplates.Elements\n\ncommon_attrs = (class = \"btn\", type = \"button\")\n@render @button {id = \"submit\", common_attrs...} \"Submit\"\n\nMain.display_html(ans) #hide","title":"Attribute Spreading"},{"category":"section","location":"core-concepts/#Boolean-Attributes","page":"Core Concepts","text":"Boolean handling follows HTML5 semantics:\n\nusing HypertextTemplates\nusing HypertextTemplates.Elements\n\n# true renders the attribute name only\n@render @input {type = \"checkbox\", checked = true}\n\nMain.display_html(ans) #hide\n\n# false omits the attribute entirely\n@render @input {type = \"checkbox\", checked = false}\n\nMain.display_html(ans) #hide","title":"Boolean Attributes"},{"category":"section","location":"core-concepts/#Text-Rendering-and-Interpolation","page":"Core Concepts","text":"","title":"Text Rendering and Interpolation"},{"category":"section","location":"core-concepts/#Variable-Interpolation-with","page":"Core Concepts","text":"The $ syntax marks expressions for rendering with automatic escaping:\n\nusing HypertextTemplates\nusing HypertextTemplates.Elements\n\nuser_input = \"<script>alert('xss')</script>\"\nhtml = @render @p \"User said: \" $user_input\n\nMain.display_html(html) #hide","title":"Variable Interpolation with $"},{"category":"section","location":"core-concepts/#The-@text-Macro","page":"Core Concepts","text":"The $ syntax is actually shorthand for @text:\n\nusing HypertextTemplates\nusing HypertextTemplates.Elements\n\nvalue = 42\n\n# These are equivalent\nhtml1 = @render @p \"\\$ Value: \" $value\n\nMain.display_html(html1) #hide\n\nhtml2 = @render @p \"@text Value: \" @text value\n\nMain.display_html(html2) #hide\n\na, b = 10, 20\n# @text can handle complex expressions\nhtml3 = @render @p @text \"The sum is $(a + b)\"\n\nMain.display_html(html3) #hide","title":"The @text Macro"},{"category":"section","location":"core-concepts/#Mixed-Content","page":"Core Concepts","text":"You can mix different content types:\n\nusing HypertextTemplates\nusing HypertextTemplates.Elements\n\ndynamic_var = \"dynamic content\"\n\nhtml = @render @div begin\n    @span \"Static text \"   # String literal\n    @code $dynamic_var     # Escaped variable\n    @p \"bold\"              # Nested element\n    @strong \" more text\"   # Another literal\nend\n\nMain.display_html(html) #hide","title":"Mixed Content"},{"category":"section","location":"core-concepts/#Zero-Allocation-Design","page":"Core Concepts","text":"The performance benefits of the macro system extend to the rendering pipeline through zero-allocation design:","title":"Zero-Allocation Design"},{"category":"section","location":"core-concepts/#Direct-IO-Streaming","page":"Core Concepts","text":"Instead of building a DOM tree, content streams directly to IO:\n\nusing HypertextTemplates\nusing HypertextTemplates.Elements\n\n# No intermediate string allocations\nio = IOBuffer()\n@render io @div begin\n    for i in 1:5\n        @p \"Paragraph \" $i\n    end\nend\n\nresult = String(take!(io))\n\nMain.display_html(result) #hide","title":"Direct IO Streaming"},{"category":"section","location":"core-concepts/#Efficient-String-Building","page":"Core Concepts","text":"The rendering process uses Julia's efficient IO system:\n\nusing HypertextTemplates\nusing HypertextTemplates.Elements\n\n# Internally uses write() calls, not string concatenation\nhtml = @render @div begin\n    @h1 \"Title\"\n    @p \"Content\"\nend\n\nMain.display_html(html) #hide\n\n# This is equivalent to direct write() calls:\n# write(io, \"<div>\")\n# write(io, \"<h1>\")\n# write(io, \"Title\")\n# write(io, \"</h1>\")\n# ...","title":"Efficient String Building"},{"category":"section","location":"core-concepts/#Rendering-Pipeline","page":"Core Concepts","text":"The rendering pipeline works as follows:\n\nMacro Expansion: Templates are transformed into Julia code at compile time\nIO Target: All output goes to an IO stream (provided or created)\nDirect Writing: HTML strings and escaped content are written directly\nNo Buffering: Content flows straight through without intermediate storage\n\nThis design means:\n\nMemory usage is constant regardless of output size\nFirst byte is written immediately (no buffering)\nSuitable for very large documents\nOptimal for streaming responses","title":"Rendering Pipeline"},{"category":"section","location":"core-concepts/#Control-Flow-Integration","page":"Core Concepts","text":"Since templates are Julia code, all control flow constructs work naturally:","title":"Control Flow Integration"},{"category":"section","location":"core-concepts/#Loops","page":"Core Concepts","text":"using HypertextTemplates\nusing HypertextTemplates.Elements\n\n# for loops\ncollection = [\"Apple\", \"Banana\", \"Cherry\"]\nhtml1 = @render @ul for item in collection\n    @li $item\nend\n\nMain.display_html(html1) #hide\n\n# while loops\ncount = 0\nhtml2 = @render @div begin\n    while count < 3\n        @p \"Count: \" $count\n        global count += 1\n    end\nend\n\nMain.display_html(html2) #hide\n\n# comprehensions\nhtml3 = @render @select begin\n    [@option {value = i} \"Option \" $i for i in 1:5]\nend\nprintln(\"\\nComprehension:\")\nMain.display_html(html3) #hide","title":"Loops"},{"category":"section","location":"core-concepts/#Conditionals","page":"Core Concepts","text":"All conditional forms are supported:\n\nusing HypertextTemplates\nusing HypertextTemplates.Elements\n\n# if-else\ncondition = true\nhtml1 = @render @div begin\n    if condition\n        @p \"True branch\"\n    else\n        @p \"False branch\"\n    end\nend\n\nMain.display_html(html1) #hide\n\n# ternary operator\nisactive = false\nhtml2 = @render @p {class = isactive ? \"active\" : \"inactive\"} \"Status\"\n\nMain.display_html(html2) #hide\n\n# short-circuit evaluation\nhasdata = false\nhtml3 = @render @div begin\n    hasdata && @p \"Data is available\"\n    !hasdata && @p \"No data available\"\nend\n\nMain.display_html(html3) #hide","title":"Conditionals"},{"category":"section","location":"core-concepts/#Pattern-Matching","page":"Core Concepts","text":"Works with any macro-based control flow:\n\n# With Match.jl (example)\n@div begin\n    @match value begin\n        1 => @p \"One\"\n        2 => @p \"Two\"\n        _ => @p \"Other\"\n    end\nend","title":"Pattern Matching"},{"category":"section","location":"core-concepts/#Component-Architecture","page":"Core Concepts","text":"The macro system and control flow integration come together in HypertextTemplates' component architecture:","title":"Component Architecture"},{"category":"section","location":"core-concepts/#Function-Based-Components","page":"Core Concepts","text":"using HypertextTemplates\nusing HypertextTemplates.Elements\n\n@component function alert(; type = \"info\", message)\n    classes = \"alert alert-\" * type\n    @div {class = classes, role = \"alert\"} $message\nend\n\n@deftag macro alert end\n\n# Use the component\nhtml = @render @alert {type = \"warning\", message = \"This is a warning!\"}\n\nMain.display_html(html) #hide","title":"Function-Based Components"},{"category":"section","location":"core-concepts/#Composition","page":"Core Concepts","text":"Components compose naturally:\n\nusing HypertextTemplates\nusing HypertextTemplates.Elements\n\n# Reuse the alert component from above\n@component function alert(; type = \"info\", message)\n    classes = \"alert alert-\" * type\n    @div {class = classes, role = \"alert\"} $message\nend\n\n@deftag macro alert end\n\n@component function alert_list(; alerts)\n    @div {class = \"alert-container\"} begin\n        for alert in alerts\n            @alert {type = alert.type, message = alert.message}\n        end\n    end\nend\n\n@deftag macro alert_list end\n\n# Use the composed component\nalerts = [\n    (type = \"info\", message = \"Information message\"),\n    (type = \"warning\", message = \"Warning message\"),\n    (type = \"error\", message = \"Error message\")\n]\n\nhtml = @render @alert_list {alerts}\n\nMain.display_html(html) #hide","title":"Composition"},{"category":"section","location":"core-concepts/#Component-Transformation","page":"Core Concepts","text":"The @component macro transforms the function to:\n\nAccept rendering context (IO stream)\nHandle slot content (both default and named slots)\nManage source location tracking (in development mode)\nSupport streaming render (for async operations)\n\nFor example, this component:\n\n@component function example(; prop)\n    @div $prop\nend\n\nIs transformed into a function that:\n\nAccepts an internal __io__ parameter for rendering\nCan receive slot content via hidden parameters\nTracks its definition location for debugging\nWorks seamlessly with StreamingRender","title":"Component Transformation"},{"category":"section","location":"core-concepts/#Performance-Considerations","page":"Core Concepts","text":"The zero-allocation design and macro system combine to optimize performance at multiple levels:","title":"Performance Considerations"},{"category":"section","location":"core-concepts/#Compile-Time-Work","page":"Core Concepts","text":"using HypertextTemplates\nusing HypertextTemplates.Elements\n\n# This template structure is analyzed at compile time\n@component function static_heavy()\n    @div {class = \"wrapper\"} begin\n        @header begin\n            @nav begin\n                @ul begin\n                    @li @a {href = \"/\"} \"Home\"\n                    @li @a {href = \"/about\"} \"About\"\n                end\n            end\n        end\n    end\nend\n\n@deftag macro static_heavy end\n\n# The structure is compiled, not interpreted at runtime\nhtml = @render @static_heavy\n\nMain.display_html(html) #hide","title":"Compile-Time Work"},{"category":"section","location":"core-concepts/#Runtime-Efficiency","page":"Core Concepts","text":"Only dynamic parts are computed at runtime:\n\nusing HypertextTemplates\nusing HypertextTemplates.Elements\n\n@component function dynamic_list(; items)\n    # Static structure compiled, only loop runs at runtime\n    @ul {class = \"list\"} begin\n        for item in items  # Only this loop runs at runtime\n            @li $item\n        end\n    end\nend\n\n@deftag macro dynamic_list end\n\n# Only the loop execution is runtime work\nitems = [\"Dynamic 1\", \"Dynamic 2\", \"Dynamic 3\"]\nhtml = @render @dynamic_list {items}\n\nMain.display_html(html) #hide","title":"Runtime Efficiency"},{"category":"section","location":"core-concepts/#HTML-Escaping-Strategy","page":"Core Concepts","text":"Complementing the performance features, HypertextTemplates provides automatic security through its escaping strategy:","title":"HTML Escaping Strategy"},{"category":"section","location":"core-concepts/#Automatic-Escaping","page":"Core Concepts","text":"All dynamic content is escaped by default:\n\nusing HypertextTemplates\nusing HypertextTemplates.Elements\n\nunsafe = \"<script>alert('xss')</script>\"\nhtml = @render @p $unsafe\n\nMain.display_html(html) #hide","title":"Automatic Escaping"},{"category":"section","location":"core-concepts/#Escape-Rules","page":"Core Concepts","text":"String literals in templates are NOT escaped (trusted content)\nVariables and expressions with $ or @text ARE escaped\nAttribute values from variables ARE escaped\nElement content from components is already rendered (not double-escaped)","title":"Escape Rules"},{"category":"section","location":"core-concepts/#Performance","page":"Core Concepts","text":"Escaping uses optimized routines:\n\nFast-path for strings without special characters\nEfficient replacement for strings with special characters\nMinimal allocations during escaping","title":"Performance"},{"category":"section","location":"core-concepts/#Summary","page":"Core Concepts","text":"These core concepts build on each other:\n\nMacros provide the foundation with compile-time optimization\n{} attributes extend the macro syntax for properties\nText rendering handles content with automatic security\nZero-allocation design ensures performance at scale\nControl flow integration leverages Julia's expressiveness\nComponents combine all concepts for reusable templates\n\nEach concept reinforces the others, creating a cohesive system that's fast, safe, and natural to use.","title":"Summary"},{"category":"section","location":"advanced-features/#Advanced-Features","page":"Advanced Features","text":"This guide covers advanced features in HypertextTemplates.jl that enable sophisticated template patterns and optimizations.","title":"Advanced Features"},{"category":"section","location":"advanced-features/#The-@__once__-Macro","page":"Advanced Features","text":"The @__once__ macro ensures content is rendered only once per @render call, even if the component is used multiple times.","title":"The @__once__ Macro"},{"category":"section","location":"advanced-features/#Basic-Usage","page":"Advanced Features","text":"The @__once__ macro is a powerful deduplication tool that ensures specific content (like CSS styles, JavaScript libraries, or initialization code) is only rendered once within a single @render call, even if the component containing it is used multiple times. This is essential for preventing duplicate script tags, style definitions, or other resources that should only appear once in your HTML output. The macro tracks what has been rendered and automatically skips subsequent occurrences within the same rendering context.\n\nusing HypertextTemplates\nusing HypertextTemplates.Elements\n\n@component function include_jquery()\n    @__once__ begin\n        @script {src = \"https://code.jquery.com/jquery-3.6.0.min.js\"}\n    end\nend\n\n@deftag macro include_jquery end\n\n# The script tag appears only once in the output\nhtml = @render @div begin\n    @include_jquery  # Renders script\n    @include_jquery  # Skips script (already rendered)\n    @include_jquery  # Skips script (already rendered)\nend\n\nMain.display_html(html) #hide\n# Note: Only one script tag appears!","title":"Basic Usage"},{"category":"section","location":"advanced-features/#Common-Use-Cases","page":"Advanced Features","text":"","title":"Common Use Cases"},{"category":"section","location":"advanced-features/#CSS-Dependencies","page":"Advanced Features","text":"using HypertextTemplates\nusing HypertextTemplates.Elements\n\n@component function styled_button(; text, variant = \"primary\")\n    @__once__ begin\n        @style \"\"\"\n        .btn {\n            padding: 0.5rem 1rem;\n            border: none;\n            border-radius: 0.25rem;\n            cursor: pointer;\n        }\n        .btn-primary { background: #007bff; color: white; }\n        .btn-danger { background: #dc3545; color: white; }\n        \"\"\"\n    end\n    \n    @button {class = \"btn btn-$variant\"} $text\nend\n\n@deftag macro styled_button end\n\n# Style block rendered once, buttons rendered multiple times\nhtml = @render @div begin\n    @styled_button {text = \"Save\", variant = \"primary\"}\n    @styled_button {text = \"Delete\", variant = \"danger\"}\n    @styled_button {text = \"Cancel\"}\nend\nMain.display_html(html) #hide\n# Note: The <style> block appears only once at the beginning!","title":"CSS Dependencies"},{"category":"section","location":"advanced-features/#JavaScript-Initialization","page":"Advanced Features","text":"using HypertextTemplates\nusing HypertextTemplates.Elements\n\n@component function data_table(; id, data)\n    @__once__ begin\n        @script \"\"\"\n        function initDataTable(id) {\n            // Initialize table sorting, filtering, etc.\n            console.log('Initializing table:', id);\n        }\n        \"\"\"\n    end\n    \n    @table {id} begin\n        @thead @tr begin\n            @th \"Name\"\n            @th \"Value\"\n        end\n        @tbody begin\n            for item in data\n                @tr begin\n                    @td $(item.name)\n                    @td $(item.value)\n                end\n            end\n        end\n    end\n    \n    @script \"initDataTable('$id');\"\nend\n\n@deftag macro data_table end\n\n# Multiple tables, but init function defined once\ndata1 = [(name = \"A\", value = 1), (name = \"B\", value = 2)]\ndata2 = [(name = \"X\", value = 10), (name = \"Y\", value = 20)]\n\nhtml = @render @div begin\n    @data_table {id = \"table1\", data = data1}\n    @data_table {id = \"table2\", data = data2}\nend\n\nMain.display_html(html) #hide\n# Note: initDataTable function defined once, but called twice","title":"JavaScript Initialization"},{"category":"section","location":"advanced-features/#Scoping-Behavior","page":"Advanced Features","text":"@__once__ is scoped to the current render context:\n\nusing HypertextTemplates\nusing HypertextTemplates.Elements\n\n@component function scoped_script()\n    @__once__ begin\n        @script \"console.log('Script loaded');\"\n    end\n    @p \"Component rendered\"\nend\n\n@deftag macro scoped_script end\n\n# First render - includes script\nhtml1 = @render @div begin\n    @scoped_script\nend\nMain.display_html(html1) #hide\n\n# Second render - includes script again (different render context)\nhtml2 = @render @div begin\n    @scoped_script  \nend\nMain.display_html(html2) #hide\n\n# Within same render - deduplication works\nhtml3 = @render @div begin\n    @section @scoped_script  # Included\n    @section @scoped_script  # Skipped\nend\nMain.display_html(html3) #hide","title":"Scoping Behavior"},{"category":"section","location":"advanced-features/#The-@deftag-Macro","page":"Advanced Features","text":"Create custom macros for components and elements for cleaner syntax.","title":"The @deftag Macro"},{"category":"section","location":"advanced-features/#Basic-Definition","page":"Advanced Features","text":"The @deftag macro transforms your components and custom elements into first-class DSL elements that can be used with the same clean syntax as built-in HTML elements. Instead of calling components as functions, @deftag creates a macro that integrates seamlessly with the template syntax, supporting attributes in {} blocks and content blocks just like @div or @p. This makes your custom components feel native to the templating language and improves code readability.\n\nusing HypertextTemplates\nusing HypertextTemplates.Elements\n\n# Define a component\n@component function alert(; type = \"info\", dismissible = false)\n    @div {class = \"alert alert-$type\"} begin\n        @__slot__\n        if dismissible\n            @button {class = \"close\"} \"×\"\n        end\n    end\nend\n\n# Create a macro for it\n@deftag macro alert end\n\n# Now use as a regular element macro\nhtml = @render @alert {type = \"warning\", dismissible = true} begin\n    @strong \"Warning!\" \" Something went wrong.\"\nend\nMain.display_html(html) #hide\n\n# Also works without dismissible\nhtml2 = @render @alert {type = \"info\"} \"This is an info message.\"\nMain.display_html(html2) #hide","title":"Basic Definition"},{"category":"section","location":"advanced-features/#Custom-Element-Tags","page":"Advanced Features","text":"using HypertextTemplates\nusing HypertextTemplates.Elements\n\n# Define custom elements with macros\n@element \"my-custom-element\" my_custom_element\n@deftag macro my_custom_element end\n\n# Use the custom element\nhtml = @render @my_custom_element {prop = \"value\"} \"Content\"\nMain.display_html(html) #hide\n\n# Also works with nested content\n@element \"custom-card\" custom_card\n@deftag macro custom_card end\n\nhtml2 = @render @custom_card {variant = \"primary\"} begin\n    @h3 \"Card Title\"\n    @p \"Card content goes here\"\nend\nMain.display_html(html2) #hide","title":"Custom Element Tags"},{"category":"section","location":"advanced-features/#Module-Scoped-Tags","page":"Advanced Features","text":"using HypertextTemplates\nusing HypertextTemplates.Elements\n\nmodule UI\n    using HypertextTemplates\n    using HypertextTemplates.Elements\n\n    @component function button(; variant = \"default\")\n        Elements.@button {class = \"ui-btn ui-btn-$variant\"} @__slot__\n    end\n\n    # Create and export the macro\n    @deftag macro button end\n    export @button\nend\n\n# Use from outside the module\nhtml = @render @UI.button {variant = \"primary\"} \"Click me\"\nMain.display_html(html) #hide\n\n# Also can import and use directly\nusing .UI: @button\nhtml2 = @render @button {variant = \"success\"} \"Save\"\nMain.display_html(html2) #hide","title":"Module-Scoped Tags"},{"category":"section","location":"advanced-features/#Text-Interpolation-with","page":"Advanced Features","text":"The $ syntax provides convenient text interpolation, similar to string interpolation.","title":"Text Interpolation with $"},{"category":"section","location":"advanced-features/#Basic-Interpolation","page":"Advanced Features","text":"Text interpolation with $ provides a concise way to embed dynamic values directly within your templates, eliminating the need for explicit @text calls. This syntax works just like Julia's string interpolation but is HTML-aware, automatically escaping values for security. You can interpolate variables, expressions, and even complex computations, making your templates more readable and maintainable while maintaining the same performance and safety guarantees as explicit text nodes.\n\nusing HypertextTemplates\nusing HypertextTemplates.Elements\n\nname = \"Julia\"\nversion = 1.9\n\nhtml = @render @div begin\n    @h1 \"Welcome to \" $name \" v\" $version\nend\nMain.display_html(html) #hide\n# Equivalent to:\n# @h1 \"Welcome to \" @text name \" v\" @text version","title":"Basic Interpolation"},{"category":"section","location":"advanced-features/#Expression-Interpolation","page":"Advanced Features","text":"using HypertextTemplates\nusing HypertextTemplates.Elements\n\nitems = [\"apple\", \"banana\", \"cherry\"]\n\nhtml = @render @ul begin\n    for (i, item) in enumerate(items)\n        @li \"Item \" $i \": \" $(uppercase(item))\n    end\nend\nMain.display_html(html) #hide","title":"Expression Interpolation"},{"category":"section","location":"advanced-features/#Nested-Interpolation","page":"Advanced Features","text":"using HypertextTemplates\nusing HypertextTemplates.Elements\n\n@component function price_display(; amount, currency = \"\\$\")\n    @span {class = \"price\"} $currency $(round(amount, digits=2))\nend\n\n@deftag macro price_display end\n\nhtml = @render @div begin\n    @text \"Total: \"\n    @price_display {amount = 99.999}\n    @text \" (Tax included: \"\n    @price_display {amount = 99.999 * 1.1} \")\"\nend\nMain.display_html(html) #hide","title":"Nested Interpolation"},{"category":"section","location":"advanced-features/#Dynamic-Component-Selection","page":"Advanced Features","text":"The @< macro enables dynamic component rendering.","title":"Dynamic Component Selection"},{"category":"section","location":"advanced-features/#Component-as-Variable","page":"Advanced Features","text":"The @< macro enables dynamic component selection at runtime, allowing you to choose which component to render based on data or conditions. This pattern is essential for building flexible UIs where the component type needs to be determined programmatically - such as rendering different message types, form fields, or content blocks based on configuration. The syntax @<component_var {props} treats the component as a first-class value that can be stored in variables, passed as arguments, or selected from dictionaries.\n\nusing HypertextTemplates\nusing HypertextTemplates.Elements\n\n# Define the specific components first\n@component function error_message(; content)\n    @div {class = \"error\"} @strong \"Error: \" $content\nend\n\n@component function warning_message(; content)\n    @div {class = \"warning\"} @strong \"Warning: \" $content\nend\n\n@component function info_message(; content)\n    @div {class = \"info\"} @strong \"Info: \" $content\nend\n\n# Select component based on condition\n@component function message(; type, content)\n    component = if type == \"error\"\n        error_message\n    elseif type == \"warning\"  \n        warning_message\n    else\n        info_message\n    end\n\n    @<component {content}\nend\n\n@deftag macro message end\n\n# Usage\nhtml = @render @div begin\n    @message {type = \"error\", content = \"File not found\"}\n    @message {type = \"warning\", content = \"Disk space low\"}\n    @message {type = \"info\", content = \"Process completed\"}\nend\nMain.display_html(html) #hide","title":"Component as Variable"},{"category":"section","location":"advanced-features/#Polymorphic-Components","page":"Advanced Features","text":"using HypertextTemplates\nusing HypertextTemplates.Elements\n\n@component function flexible_container(; tag = div, class_name = \"container\")\n    @<tag {class = class_name} begin\n        @__slot__\n    end\nend\n\n@deftag macro flexible_container end\n\n# Use with different HTML elements\nhtml1 = @render @flexible_container {tag = section} begin\n    @h1 \"Section Title\"\n    @p \"Section content\"\nend\nMain.display_html(html1) #hide\n\nhtml2 = @render @flexible_container {tag = article, class_name = \"article-container\"} begin\n    @h2 \"Article Title\"\n    @p \"Article content\"\nend\nMain.display_html(html2) #hide","title":"Polymorphic Components"},{"category":"section","location":"advanced-features/#Component-Maps","page":"Advanced Features","text":"using HypertextTemplates\nusing HypertextTemplates.Elements\n\n# Define field components\n@component function text_field(; name, options = nothing)\n    @input {type = \"text\", name, id = name}\nend\n\n@component function email_field(; name, options = nothing)\n    @input {type = \"email\", name, id = name}\nend\n\n@component function select_field(; name, options = [])\n    @select {name, id = name} begin\n        for opt in options\n            @option {value = opt.value} $(opt.label)\n        end\n    end\nend\n\n# Map of field types to components\nconst FIELD_COMPONENTS = Dict(\n    :text => text_field,\n    :email => email_field,\n    :select => select_field\n)\n\n@component function form_field(; type, name, label, options = nothing)\n    component = get(FIELD_COMPONENTS, type, text_field)\n\n    @div {class = \"form-field\"} begin\n        Elements.@label {\"for\" := name} $label\n        @<component {name, options}\n    end\nend\n\n@deftag macro form_field end\n\n# Usage examples\nhtml = @render @form begin\n    @form_field {type = :text, name = \"username\", label = \"Username:\"}\n    @form_field {type = :email, name = \"email\", label = \"Email:\"}\n    @form_field {\n        type = :select,\n        name = \"country\",\n        label = \"Country:\",\n        options = [\n            (value = \"us\", label = \"United States\"),\n            (value = \"uk\", label = \"United Kingdom\"),\n            (value = \"ca\", label = \"Canada\")\n        ]\n    }\nend\n\nMain.display_html(html) #hide","title":"Component Maps"},{"category":"section","location":"advanced-features/#Advanced-Patterns","page":"Advanced Features","text":"","title":"Advanced Patterns"},{"category":"section","location":"advanced-features/#Memoization","page":"Advanced Features","text":"Cache expensive computations:\n\nusing HypertextTemplates\nusing HypertextTemplates.Elements\n\nconst COMPUTED_CACHE = Dict{Any,Any}()\n\n@component function memoized(; key, compute)\n    value = get!(COMPUTED_CACHE, key) do\n        compute()\n    end\n\n    @div {class = \"memoized\"} $value\nend\n\n@deftag macro memoized end\n\n# Simulate expensive calculation\nfunction expensive_calculation(id)\n    println(\"Computing for id=$id...\")\n    return \"Result for $id\"\nend\n\n# First call computes\nhtml1 = @render @memoized {\n    key = \"expensive-42\",\n    compute = () -> expensive_calculation(42)\n}\nprintln(\"First render: \", html1)\n\n# Second call uses cache (no \"Computing...\" message)\nhtml2 = @render @memoized {\n    key = \"expensive-42\",\n    compute = () -> expensive_calculation(42)\n}\nprintln(\"Second render (cached): \", html2)\n\n# Different key computes again\nhtml3 = @render @memoized {\n    key = \"expensive-99\",\n    compute = () -> expensive_calculation(99)\n}\nprintln(\"Different key: \", html3)","title":"Memoization"},{"category":"section","location":"advanced-features/#Render-Props-Pattern","page":"Advanced Features","text":"Pass rendering functions as props:\n\nusing HypertextTemplates\nusing HypertextTemplates.Elements\n\n# Simulate data fetching\nfunction fetch_data(url)\n    if url == \"/api/users\"\n        # Simulate successful fetch\n        data = [(name = \"Alice\",), (name = \"Bob\",), (name = \"Charlie\",)]\n        return (data = data, error = nothing, loading = false)\n    elseif url == \"/api/error\"\n        return (data = nothing, error = \"Network error\", loading = false)\n    else\n        return (data = nothing, error = nothing, loading = true)\n    end\nend\n\n@component function data_fetcher(; url, render_loading, render_error, render_success)\n    result = fetch_data(url)\n\n    if result.loading\n        @<render_loading\n    elseif !isnothing(result.error)\n        @<render_error {error = result.error}\n    else\n        @<render_success {data = result.data}\n    end\nend\n\n@deftag macro data_fetcher end\n\n# Define render components\n@component function loading_comp()\n    @p {class = \"loading\"} \"Loading...\"\nend\n@component function error_comp(; error)\n    @p {class = \"error\"} \"Error: \" $error\nend\n@component function success_comp(; data)\n    @ul begin\n        for user in data\n            @li $(user.name)\n        end\n    end\nend\n\n# Success case\nprintln(\"Success case:\")\nhtml1 = @render @data_fetcher {\n    url = \"/api/users\",\n    render_loading = loading_comp,\n    render_error = error_comp,\n    render_success = success_comp\n}\nMain.display_html(html1) #hide\n\n# Error case\nprintln(\"\\nError case:\")\nhtml2 = @render @data_fetcher {\n    url = \"/api/error\",\n    render_loading = loading_comp,\n    render_error = error_comp,\n    render_success = success_comp\n}\nMain.display_html(html2) #hide","title":"Render Props Pattern"},{"category":"section","location":"advanced-features/#Template-Inheritance","page":"Advanced Features","text":"Build template inheritance systems:\n\nusing HypertextTemplates\nusing HypertextTemplates.Elements\n\n@component function base_layout(; title = \"Default Title\")\n    @html begin\n        @head begin\n            @title $title\n            @__slot__ head  # Additional head content\n        end\n        @body begin\n            @header @__slot__ header\n            Elements.@main @__slot__     # Default slot for main content\n            @footer @__slot__ footer\n        end\n    end\nend\n\n@deftag macro base_layout end\n\n@component function blog_layout(; post)\n    @base_layout {title = post.title} begin\n        # Main content\n        @article begin\n            @h1 $(post.title)\n            @div {class = \"content\"} $(SafeString(post.html))\n        end\n\n        # Named slots\n        head := @meta {name = \"author\", content = post.author}\n\n        header := @nav @a {href = \"/blog\"} \"← Back to Blog\"\n\n        footer := @p \"Published: \" $(post.date)\n    end\nend\n\n@deftag macro blog_layout end\n\n# Example blog post\npost = (\n    title = \"Understanding Julia Macros\",\n    author = \"Jane Developer\",\n    date = \"2024-01-15\",\n    html = \"<p>Julia macros are powerful metaprogramming tools...</p>\"\n)\n\nhtml = @render @blog_layout {post}\nMain.display_html(html) #hide","title":"Template Inheritance"},{"category":"section","location":"advanced-features/#Lazy-Loading-Pattern","page":"Advanced Features","text":"Load data on-demand during rendering:\n\nusing HypertextTemplates\nusing HypertextTemplates.Elements\n\nconst DATA_CACHE = Dict{Any,Any}()\n\n# Simulate database fetch\nfunction fetch_users_from_db()\n    println(\"Fetching from database...\")\n    return [\n        (name = \"Alice\", id = 1),\n        (name = \"Bob\", id = 2),\n        (name = \"Charlie\", id = 3)\n    ]\nend\n\n@component function lazy_data(; data_loader, cache_key = nothing)\n    # Load data during render (blocking)\n    data = if !isnothing(cache_key) && haskey(DATA_CACHE, cache_key)\n        println(\"Using cached data for key: $cache_key\")\n        DATA_CACHE[cache_key]\n    else\n        result = data_loader()\n        if !isnothing(cache_key)\n            DATA_CACHE[cache_key] = result\n        end\n        result\n    end\n\n    @div {class = \"data-container\"} begin\n        if isempty(data)\n            @p {class = \"empty\"} \"No data available\"\n        else\n            @ul begin\n                for item in data\n                    @li \"$(item.name) (ID: $(item.id))\"\n                end\n            end\n        end\n    end\nend\n\n@deftag macro lazy_data end\n\n# First render - fetches data\nprintln(\"First render:\")\nhtml1 = @render @lazy_data {\n    cache_key = \"users\",\n    data_loader = () -> fetch_users_from_db()\n}\nMain.display_html(html1) #hide\n\n# Second render - uses cache\nprintln(\"\\nSecond render:\")\nhtml2 = @render @lazy_data {\n    cache_key = \"users\",\n    data_loader = () -> fetch_users_from_db()\n}\nMain.display_html(html2) #hide","title":"Lazy Loading Pattern"},{"category":"section","location":"advanced-features/#Best-Practices","page":"Advanced Features","text":"Use @__once__ for dependencies - Include CSS/JS dependencies once\nCreate domain-specific tags - Use @deftag for common patterns\nLeverage $ interpolation - Cleaner than multiple @text calls\nCache expensive operations - Use memoization for complex computations","title":"Best Practices"},{"category":"section","location":"advanced-features/#Summary","page":"Advanced Features","text":"Advanced features in HypertextTemplates.jl enable:\n\nDependency management with @__once__\nCustom DSLs via @deftag\nDynamic rendering with @<\nSophisticated patterns like render props\n\nThese features combine to support complex application architectures while maintaining the simplicity and performance that makes HypertextTemplates.jl powerful.","title":"Summary"},{"category":"section","location":"#HypertextTemplates.jl","page":"Home","text":"HTML templating system for Julia\n\nHypertextTemplates.jl is a powerful and efficient HTML templating system that lets you write HTML using Julia's macro syntax. It provides zero-allocation rendering, a sophisticated component system, and seamless integration with Julia's ecosystem.","title":"HypertextTemplates.jl"},{"category":"section","location":"#Key-Features","page":"Home","text":"Natural Syntax - Write HTML using Julia macros that feel like native code\nZero-allocation rendering - Direct IO streaming without intermediate DOM construction\nComponent System - Build reusable components with props and slots\nAutomatic HTML escaping - Automatic XSS protection with context-aware escaping\nDevelopment tools - Source location tracking and editor integration\nStreaming rendering - Asynchronous rendering with micro-batched output\nMarkdown Support - Create components from Markdown files","title":"Key Features"},{"category":"section","location":"#Quick-Start","page":"Home","text":"using HypertextTemplates\nusing HypertextTemplates.Elements\n\n# Simple example\nhtml = @render @div {class = \"container\"} begin\n    @h1 \"Welcome to HypertextTemplates!\"\n    @p \"Build fast, secure web applications with Julia.\"\nend\n\nMain.display_html(ans) #hide\n\n# Component example\n@component function article_card(; title, author, content)\n    @article {class = \"card\"} begin\n        @header begin\n            @h2 {class = \"card-title\"} $title\n            @p {class = \"author\"} \"by \" $author\n        end\n        @div {class = \"card-body\"} $content\n    end\nend\n@deftag macro article_card end\n\n# Use the component\n@render @article_card {\n    title = \"Hello\",\n    author = \"Julia Developer\",\n    content = \"This is a reusable component!\"\n}\n\nMain.display_html(ans) #hide","title":"Quick Start"},{"category":"section","location":"#Documentation","page":"Home","text":"","title":"Documentation"},{"category":"section","location":"#Getting-Started","page":"Home","text":"Getting Started Guide - Installation and first steps\nCore Concepts - Understanding the fundamentals","title":"Getting Started"},{"category":"section","location":"#Building-Applications","page":"Home","text":"Components Guide - Creating reusable UI components\nElements & Attributes - Working with HTML elements\nRendering & Performance - Optimization and streaming","title":"Building Applications"},{"category":"section","location":"#Advanced-Topics","page":"Home","text":"Advanced Features - Once rendering, dynamic components\nMarkdown Integration - Using Markdown with templates","title":"Advanced Topics"},{"category":"section","location":"#API-Reference","page":"Home","text":"API Reference - Complete API documentation","title":"API Reference"}]
}
